import sailpoint.object.Filter;

//Filter based on Identity attributes and privileged item extended attributes
Filter attributeFilter = null;
if ("Accounting".equals(requester.getAttribute("Department"))) {
   attributeFilter = Filter.eq("extended1", "accountingKey");
}

//Filter to include privileged items that have a specific classification on them
Filter classificationFilter = Filter.eq("classifications.classification.name","ClassificationOne");

if (attributeFilter != null) {
   filter = Filter.and(attributeFilter, classificationFilter);
} else {
   filter = classificationFilter;
}

return filter;

