public static void buildApprovalList(String idenName,List itemList){
  Identity identity = context.getObjectByName(Identity.class,idenName);
  boolean flag = identity.isInactive();
  Approval approval =  new Approval();
  ApprovalSet apprSet = new ApprovalSet();
  apprSet.setItems(itemList);
  approval.setApprovalSet(apprSet);
  if(flag == false){
    approval.setOwner(idenName);
    newApprovals.add(approval);
  }
}

List newApprovals = new ArrayList();

for (Approval approval : approvals){
  if(null != approval){
    ApprovalSet approvalSet = approval.getApprovalSet();
    List approvalItems = approvalSet.getItems();
    List itemsListAD = new ArrayList();
    List itemsListWeb = new ArrayList();
    for (ApprovalItem items : approvalItems){
      if("ActiveDirectory".equalsIgnoreCase(items.getApplicationName())){
        itemsListAD.add(items);
      }
      if("WebService Application".equalsIgnoreCase(items.getApplicationName())){
        itemsListWeb.add(items);
      }
    }

    Map itemsList = new HashMap();
    itemsList.put("Amanda Ross",itemsListAD);
    itemsList.put("Amy Cox",itemsListWeb);
    for (Map.Entry map : itemsList.entrySet()){
      String name = map.getKey();
      List list = map.getValue();
      buildApprovalList(name, list);
    }
  }
}
return newApprovals;


