private Identity getIdentityByPosition(SailPointContext context, String positionID) {
  serilog.debug("Fetching identity by position: PositionID=" + positionID);
  QueryOptions queryOptions = new QueryOptions();
  Filter filterInactive = Filter.eq("inactive", false);
  Filter filterPosition = Filter.eq("positionID", positionID);
  queryOptions.addFilter(filterInactive.and(filterPosition));
  List identities = context.getObjects(Identity.class, queryOptions);
  if(!identities.isEmpty()){
    serilog.debug("Fetched Identity: " + identities.get(0));
    return identities.get(0);
  } else {
    serilog.debug("not Fetched identity by position: PositionID=" + positionID);
    return "spadmin";
  }
}

private String getPositionID(String functionModule) {
  serilog.debug("Getting position ID for function module: " + functionModule);
  switch (functionModule) {
    case "ESS": case "HR": return "50000502";
    case "CPW": return "50056204";
    case "F&A": case "FI": return "50001217";
    case "MM": case "SD": return "50001260";
    case "EHSM": case "EHS": return "50000389";
    case "MAINT": case "MOC": case "PM": return "50001027";
    case "OPS": return "50000570";
    case "PS": case "TECH": return "50000150";
    default: return "spadmin";
  }
}

private String getFunctionModulePositionID(String functionModule) {
  serilog.debug("Getting function module position ID for: " + functionModule);
  switch (functionModule) {
    case "ESS": case "HR": return "50060748";
    case "CPW": case "F&A": case "FI": return "50033176";
    case "EHSM": case "EHS": case "MAINT": case "MOC": case "PM": return "50035926";
    default: return "spadmin";
  }
}

private Identity getIdentityByJobTitle(SailPointContext context, String jobTitle, Filter filterInactive) {
  serilog.debug("Fetching identity by job title: JobTitle=" + jobTitle);
  QueryOptions queryOptions = new QueryOptions();
  queryOptions.addFilter(filterInactive.and(Filter.eq("jobTitle", jobTitle)));
  List identities = context.getObjects(Identity.class,queryOptions);
  if(!identities.isEmpty()){
    serilog.debug("Fetched Identity: " + identities.get(0));
    return identities.get(0);
  } else {
    serilog.debug("not Fetched identity by JobTitle: JobTitle=" + jobTitle);
    return "spadmin";
  }
}
private Identity getVPIdentity(SailPointContext context,Identity requester){
  Identity VPmanager = requester.getManager();
  while (VPmanager != null){
    if ("President and Chief Executive Officer".equals(VPmanager.getAttribute("jobTitle"))){
      return VPmanager.getDisplayName();
    }
    if ("President and Chief Executive Officer".equals(VPmanager.getManager().getAttribute("jobTitle"))){
      return VPmanager.getDisplayName();
    }

    VPmanager = VPmanager.getManager();
  }
  return context.getObjectByName(Identity.class, "spadmin");
}

private Boolean isRefinary(Identity requester){
  String costCenter = requester.getAttribute("jobTitle");
  switch(costCenter){
    case "EVP Manufacturing Expenses": case "LPS": case "Maintenace Supervision & General": case "Material Control / Warehouse Expenses": case "Opertng Supvsn & Gen": case "SHARP Project": case "Tech Supvsn & Gen": case "Turnaround": return true;
    default: return false;
  }
}

