        Identity appOwner = entitlementECC.getApplication().getOwner();
        addApproval(newApprovals, "Data Owner Approval", appOwner, identityName, approvalSet, item);
      }

      String functionOwnerPositionID = getFunctionModulePositionID(functionModule);
