        addApproval(newApprovals, "Manager Approval", manager, identityName, approvalSet, item);
        addApproval(newApprovals, "AD Team Approval", activeDirectory.getOwner(), identityName, approvalSet, item);
      }
    } else {
      serilog.debug("Handling generic approval.");
      addApproval(newApprovals, "Manager Approval", manager, identityName, approvalSet, item);
      Application application = context.getObjectByName(Application.class, appName);
      addApproval(newApprovals, "Application Owner Approval", application.getOwner(), identityName, approvalSet, item);
    }
  }
  serilog.debug("Returning new approvals list.");
  return newApprovals;

} catch (Exception e) {
  serilog.error("Error processing approvals", e);
  throw new RuntimeException("Error processing approvals", e);
}
