public Map getDeptValue(String accountName,Date date){

  long longDate1 = date.getTime();
  Date date1 = new Date(longDate1);
  long twoDaysInMillis = 2 * 24 * 60 * 60 * 1000; 
  long longDate2 = longDate1+twoDaysInMillis;
  Date date2 = new Date(longDate2);
  Map map = new HashMap();

  SailPointContext ahContext = null;

  try {
    ahContext = AccessHistoryUtil.getAccessHistoryContext();
  }
  catch(Throwable T) {
    ahContext = SailPointFactory.createContext(DatabaseInstance.ACCESS_HISTORY);
  }

  QueryOptions queryOp = new QueryOptions();
  queryOp.add(Filter.and(Filter.eq("entityName", accountName), Filter.eq("eventType", HistoricalEvent.EventType.IdentityChanged)));
  queryOp.add(Filter.ge("created",date1));
  queryOp.add(Filter.le("created",date2));

  Iterator it = ahContext.search(HistoricalIdentityEvent.class,queryOp);
  while(it.hasNext()){ 
    HistoricalIdentityEvent event= it.next();
    if(event.getPropertyName().equalsIgnoreCase("department")){
      map.put("olddept",event.getOldValue()); 
      map.put("newdept",event.getNewValue()); 
    }
    if(event.getPropertyName().equalsIgnoreCase("WBWORKOUI")){
      map.put("oldVPU",event.getOldValue()); 
      map.put("newVPU",event.getNewValue()); 
    }
  }
  return map;
}


public Certification getCertification(String id){
  Certification certification = null;
  QueryOptions qo = new QueryOptions();		
  qo.add(Filter.eq("certificationGroups.id", id));
  qo.add(Filter.eq("type", "Focused"));
  qo.setCloneResults(true);
  List certificationList = context.getObjects(Certification.class,qo);

  if(certificationList != null @and certificationList.size()>0){
    certification = certificationList.get(0);
  }
  return certification;
}

