  /**
 * Gets owner names, entitlements, or both from grouped entitlement data
 * @param ownerMaps  List<Map> where each map is {ownerName: [entitlements]}
 * @param returnType "OWNER" | "ENTITLEMENTS" | "BOTH" (default)
 */
  Object getOwnerData(List ownerMaps, String returnType) {
    if (ownerMaps == null || ownerMaps.isEmpty()) {
      return Collections.EMPTY_LIST;
    }

    switch (returnType.toUpperCase()) {
      case "OWNER":
      List owners = new ArrayList();
      for (Object entry : ownerMaps) {
        Map ownerEntry = (Map) entry;
        owners.add(ownerEntry.keySet().iterator().next());
      }
      return owners;

      case "ENTITLEMENTS":
      List allEntitlements = new ArrayList();
      for (Object entry : ownerMaps) {
        Map ownerEntry = (Map) entry;
        allEntitlements.addAll((List) ownerEntry.get(ownerEntry.keySet().iterator().next()));
      }
      return allEntitlements;

      default:  // "BOTH"
      Map result = new LinkedHashMap();
      for (Object entry : ownerMaps) {
        Map ownerEntry = (Map) entry;
        String owner = ownerEntry.keySet().iterator().next();
        result.put(owner, ownerEntry.get(owner));
      }
      return result;
    }
  }

  // Overloaded version (defaults to "BOTH")
  Object getOwnerData(List ownerMaps) {
    return getOwnerData(ownerMaps, "BOTH");
  }


  // working
  private static List getEntitlementData(List newBundleProfiles) throws GeneralException {
    log.error("newBundleProfiles inside get entitlements data list method");

    // This will store {owner -> list_of_entitlement_maps}
    Map ownerGroups = new LinkedHashMap();

    QueryOptions qo = new QueryOptions();
    qo.add(Filter.in("value", newBundleProfiles));
    Iterator itr = context.search(ManagedAttribute.class, qo);

    while (itr != null && itr.hasNext()) {
      ManagedAttribute ma = (ManagedAttribute) itr.next();
      if (ma != null) {
        String ownerName = (ma.getOwner() != null && ma.getOwner().getName() != null) 
          ? ma.getOwner().getName() 
          : "UNKNOWN_OWNER";

        // Create entitlement map
        Map entitlement = new LinkedHashMap();
        entitlement.put("Application", ma.getApplication() != null ? ma.getApplication().getName() : "");
        entitlement.put("Type", ma.getType() != null ? ma.getType() : "");
        entitlement.put("Owner", ownerName);
        entitlement.put("Value", ma.getValue() != null ? ma.getValue() : "");
        entitlement.put("DisplayName", ma.getDisplayName() != null ? ma.getDisplayName() : "");
        entitlement.put("Property", ma.getAttribute() != null ? ma.getAttribute() : "");

        // Group by owner
        if (!ownerGroups.containsKey(ownerName)) {
          ownerGroups.put(ownerName, new ArrayList());
        }
        ((List)ownerGroups.get(ownerName)).add(entitlement);
      }
    }

    // Convert to List of Maps format
    List result = new ArrayList();
    for (Iterator it = ownerGroups.keySet().iterator(); it.hasNext();) {
      String owner = (String) it.next();
      Map ownerMap = new LinkedHashMap();
      ownerMap.put(owner, ownerGroups.get(owner));
      result.add(ownerMap);
    }

    log.error("Final owner entitlement list: " + result);
    return result;
  }

  private static String getEntitlementOwners(List newBundleProfiles) throws GeneralException {
    log.debug("Entered into getEntitlementOwners()");
    String ownersCsv = "";
    log.debug("newBundleProfiles: " + newBundleProfiles);
    if (Util.nullSafeSize(newBundleProfiles) > 0) {
      log.debug("newBundleProfiles is not empty, proceeding with query...");
      QueryOptions qo = new QueryOptions();
      qo.addFilter(Filter.in("value", newBundleProfiles));
      log.debug("QueryOptions prepared with filter: " + qo);
      List owners = new ArrayList();
      Iterator itr = context.search(ManagedAttribute.class, qo, "owner.name");
      if (itr == null) {
        log.warn("Iterator returned from context.search is null");
      } else {
        log.debug("Processing search results...");
      }
      while (itr != null && itr.hasNext()) {
        Object[] owner = (Object[]) itr.next();
        log.debug("Owner found: " + owner[0]);
        owners.add(owner[0]);
      }
      owners = Util.filterNulls(owners);
      log.debug("Collected owners: " + owners);
      if (Util.nullSafeSize(owners) > 0) {
        ownersCsv = Util.listToCsv(owners);
        log.debug("Converted owners list to CSV: " + ownersCsv);
      } else {
        log.warn("No owners found from profiles");
      }
    } else {
      log.warn("newBundleProfiles is empty or null");
    }
    log.debug("Exiting getEntitlementOwners() with result: " + ownersCsv);
    return ownersCsv;
  }

  private static List getBundleProfileNames(Bundle bundle) throws GeneralException {
    log.debug("Entered into getBundleProfileNames()");
    List profilesList = new ArrayList();
    if (bundle == null) {
      log.error("Bundle is null — throwing IllegalArgumentException");
      throw new IllegalArgumentException("Bundle Object should not be null or empty.");
    }
    log.debug("Bundle is valid: " + bundle);
    List<Profile> profiles = bundle.getProfiles();
    log.debug("Profiles fetched from bundle: " + profiles);
    if (Util.nullSafeSize(profiles) > 0) {
      for (Profile profile : profiles) {
        log.debug("Processing profile: " + profile);
        List<Filter> constraints = profile.getConstraints();
        log.debug("Constraints for profile: " + constraints);
        if (Util.nullSafeSize(constraints) > 0) {
          for (Filter filter : constraints) {
            log.debug("Processing filter: " + filter);
            Object filterValue = filter.getValue();
            log.debug("Filter value: " + filterValue);
            if (filterValue instanceof List) {
              log.debug("Filter value is a List, adding all");
              profilesList.addAll((Collection) filterValue);
            } else {
              log.debug("Filter value is single, adding: " + filterValue);
              profilesList.add(filterValue);
            }
          }
        } else {
          log.warn("No constraints found for profile: " + profile);
        }
      }
    } else {
      log.warn("No profiles found in bundle");
    }
    log.debug("Exiting getBundleProfileNames() with profile list: " + profilesList);
    return profilesList;
  }

  private static void setProfileToBundle(SailPointContext context, Bundle bundle, List approvedEntitlements) throws GeneralException {
    if (bundle == null && approvedEntitlements == null) {
      throw new IllegalArgumentException("Bunlde and List should not be null or empty.");
    }

    log.error("entered into setProfileToBundle() method");

    log.error("bundle XML " + bundle.toXml());

    Bundle bundleLockObj = null;
    try {
      if (null != bundle ) {
        bundleLockObj = ObjectUtil.transactionLock(context, Bundle.class, bundle.getName());
        List<Profile> profiles = bundleLockObj.getProfiles();
        List profilesList = createCompleteProfiles(approvedEntitlements);
        profiles.addAll(profilesList);
        bundleLockObj.assignProfiles(profiles);
        // bundleLockObj.setProfiles(profiles);
        context.saveObject(bundleLockObj);
      }
    } catch (GeneralException e) {
      throw new GeneralException("Exception: an error occured due to " + e.getMessage());
    } finally {
      if (null != bundleLockObj) {
        log.error("bundleLockObj--- " + bundleLockObj.toXml());
        context.commitTransaction();
        context.decache(bundleLockObj);
      }
    }
  }


  private static void bundleProfilesCleanUp(Bundle approvalObject, List approvedEntitlements) throws GeneralException {
    if (approvalObject == null && approvedEntitlements == null) {
      throw new IllegalArgumentException("Bunlde and List should not be null or empty.");
    }
    if (null != approvalObject) {
      if (Util.nullSafeSize(approvedEntitlements) > 0) {
        List profilesList = createCompleteProfiles(approvedEntitlements);
        approvalObject.assignProfiles(profilesList);
      }
    }
  }

  /*************************************************************************************************************************************************************************************************************************************************

																																																							Get Profile Data

  **************************************************************************************************************************************************************************************************************************************************/

  import java.util.*;
  import java.util.regex.*;

  /**
 * Creates profiles from entitlement maps while processing all suffixes including _0
 * @param entitlementList List of entitlement maps
 * @return List of created Profile objects
 */
  List createCompleteProfiles(List entitlementList) throws GeneralException {
    List profiles = new ArrayList();
    for (Object item : entitlementList) {
      Map entitlement = (Map) item;
      Profile profile = createProfileFromAllSuffixes(entitlement);
      if (profile != null) {
        profiles.add(profile);
      } else {
        log.warn("Preserving entitlement data (no profile created): " + entitlement);
      }
    }
    return profiles;
  }

  /**
 * Creates profile checking all possible suffixes including _0
 */
  Profile createProfileFromAllSuffixes(Map entitlement) throws GeneralException {
    if (entitlement == null) return null;
    // Get all existing suffixes including _0
    Set<Integer> suffixes = findAllSuffixes(entitlement.keySet());
    // Always check base fields (no suffix) first
    if (suffixes.contains(-1)) {  // -1 represents no suffix
      Profile profile = tryCreateProfile(entitlement, "");
      if (profile != null) return profile;
    }
    // Then check numbered suffixes in order
    for (int i = 0; i <= findMaxSuffix(entitlement.keySet()); i++) {
      if (suffixes.contains(i)) {
        Profile profile = tryCreateProfile(entitlement, "_" + i);
        if (profile != null) return profile;
      }
    }
    return null;
  }

  /**
 * Attempts profile creation with specific suffix
 */
  Profile tryCreateProfile(Map entitlement, String suffix) throws GeneralException {
    String appName = getValidValue(entitlement, "Application" + suffix);
    String property = getValidValue(entitlement, "Property" + suffix);
    String value = getValidValue(entitlement, "Value" + suffix);
    if (isValidConfig(appName, property, value)) {
      try {
        Application app = context.getObjectByName(Application.class, appName);
        if (app != null) {
          Profile profile = new Profile();
          profile.setApplication(app);
          profile.setConstraints(Arrays.asList(
            Filter.containsAll(property, Arrays.asList(value))
          ));
          return profile;
        }
      } catch (GeneralException e) {
        log.error("Profile creation failed for " + appName + ": " + e.getMessage());
      }
    }
    return null;
  }

  /**
 * Finds all numeric suffixes including _0 and base fields
 */
  Set<Integer> findAllSuffixes(Set keys) {
    Set<Integer> suffixes = new HashSet();
    for (Object keyObj : keys) {
      String key = (String) keyObj;
      if (key.startsWith("Application_")) {
        try {
          String suffix = key.replace("Application_", "");
          suffixes.add(suffix.isEmpty() ? -1 : Integer.parseInt(suffix));
        } catch (NumberFormatException e) {
          // Ignore non-numeric suffixes
        }
      } else if (key.equals("Application")) {
        suffixes.add(-1); // Flag for base field
      }
    }
    return suffixes;
  }

  /**
 * Finds the highest numeric suffix in map keys (e.g., _1, _2)
 */
  int findMaxSuffix(Set keys) {
    int max = 0;
    for (Object keyObj : keys) {
      String key = (String) keyObj;
      if (key.contains("_")) {
        try {
          int suffix = Integer.parseInt(key.substring(key.lastIndexOf("_") + 1));
          max = Math.max(max, suffix);
        } catch (NumberFormatException e) {
          // Ignore non-numeric suffixes
        }
      }
    }
    return max;
  }

  /**
 * Gets valid string value (not null/empty/"false")
 */
  String getValidValue(Map map, String key) {
    Object value = map.get(key);
    return (value != null) ? value.toString().trim() : null;
  }

  /**
 * Validates required fields
 */
  boolean isValidConfig(String app, String prop, String val) {
    return !Util.isNullOrEmpty(app) && !Util.isNullOrEmpty(prop) && !Util.isNullOrEmpty(val);
  }

  /**************************************************************************************************************************************************************************************************************

																																														Dynamic Form Helper methods					

  ***************************************************************************************************************************************************************************************************************/

  /**
	 * Builds dynamic entitlement approval form in BeanShell
	 * @param entitlementsData List of entitlement Maps
	 * @param decisionRequired Whether to include Approve/Deny radio buttons
	 * @return Configured Form object
	 */
  static Form buildDynamicApprovalForm(List entitlementsData, boolean decisionRequired) {
    Form form = new Form();
    form.setTitle("Entitlement Approval");
    List sections = new ArrayList();
    for (int i = 0; i < entitlementsData.size(); i++) {
      Map entitlement = (Map) entitlementsData.get(i);
      Section section = new Section();
      section.setColumns(3);
      section.setName("ent" + (i + 1));
      // Add all dynamic fields
      for (Iterator it = entitlement.entrySet().iterator(); it.hasNext();) {
        Map.Entry entry = (Map.Entry) it.next();
        String key = (String) entry.getKey();
        if (!key.startsWith("decision_")) {
          addDynamicField(section, key + "_" + i, entry.getValue());
        }
      }
      // Add decision field if required
      if (decisionRequired) {
        addDecisionField(section, i + 1);
      }
      sections.add(section);
    }
    form.setSections(sections);
    addFormControls(form);
    return form;
  }

  // Helper methods adapted for BeanShell
  static void addDynamicField(Section section, String key, Object value) {
    Field field = new Field();
    if (key.contains("_")) {
      // Make standard fields read-only
      if (isStandardField(key.split("_")[0])) {
        field.setReadOnly(true);
      }
      field.setDisplayName(convertToDisplayName(key.split("_")[0]));
    }
    field.setName(key);
    field.setDisplayType(Field.TYPE_STRING);
    field.setValue(value != null @and value.toString().equalsIgnoreCase("UNKNOWN_OWNER") ? "" : value.toString());
    section.add(field);
  }

  static void addDecisionField(Section section, int sectionNum) {
    Field decision = new Field();
    decision.setName("decision_" + sectionNum);
    decision.setDisplayName("Decision");
    decision.setDisplayType(Field.DISPLAY_TYPE_RADIO);
    decision.setRequired(true);
    List options = new ArrayList();
    options.add("Approve");
    options.add("Deny");
    decision.setAllowedValues(options);
    section.add(decision);
  }

  static boolean isStandardField(String fieldName) {
    return fieldName.matches("(?i)application|type|value|displayName|owner|property");
  }

  static String convertToDisplayName(String key) {
    return key.replaceAll("([A-Z])", " $1")
      .replaceAll("_", " ")
      .trim()
      .replaceAll("\\s+", " ");
  }

  static void addFormControls(Form form) {
    form.clearButtons();
    Button cancel = new Button("Cancel", "cancel");
    Button submit = new Button("Submit", "next");
    form.add(cancel);
    form.add(submit);
  }


  /**************************************************************************************************************************************************************************************************************

																																														Approved Entitlements Methods					

  ***************************************************************************************************************************************************************************************************************/

  /**
	 * Extracts approved entitlements from form submission
	 * @param form The submitted form object
	 * @return List of approved entitlement maps
	 */
  List getApprovedEntitlements(Form form) {
    List approvedEntitlements = new ArrayList();
    // Get all sections from the form
    List sections = form.getSections();
    for (int i = 0; i < sections.size(); i++) {
      Section section = (Section) sections.get(i);
      String sectionName = section.getName();
      // Only process entitlement sections
      if (sectionName.startsWith("ent")) {
        // Get the decision field value
        Field decisionField = section.getField("decision_" + (i+1));
        String decision = (String) decisionField.getValue();
        if ("Approve".equalsIgnoreCase(decision)) {
          Map entitlement = new HashMap();
          // Extract all fields from the section
          List fields = section.getFields();
          for (Iterator it = fields.iterator(); it.hasNext();) {
            Field field = (Field) it.next();
            String fieldName = field.getName();
            // Skip decision fields
            if (!fieldName.startsWith("decision_")) {
              entitlement.put(fieldName, field.getValue());
            }
          }
          approvedEntitlements.add(entitlement);
        }
      }
    }
    return approvedEntitlements;
  }


  /**
	 * Extracts approved entitlements from form submission
	 * @param form The submitted form object
	 * @return List of approved entitlement maps
	 */
  Form getApprovedForm(Form form) {
    // Get all sections from the form
    List sections = form.getSections();
    for (int i = 0; i < sections.size(); i++) {
      Section section = (Section) sections.get(i);
      String sectionName = section.getName();
      // Only process entitlement sections
      if (sectionName.startsWith("ent")) {
        // Get the decision field value
        Field decisionField = section.getField("decision_" + (i+1));
        String decision = (String) decisionField.getValue();
        if ("Deny".equalsIgnoreCase(decision)) {
          form.remove(section);
        }
      }
    }
    return form;
  }


  /**
 * Filters form to only include approved entitlements
 * @param form The submitted form object
 * @return New Form object with only approved sections
 */

