import javax.servlet.http.HttpServletRequest;
import java.io.BufferedReader;
import java.io.IOException;
import java.util.Enumeration;

log.error("Entered into AW - SSOValidation Rule");

// Method to print parameters
void logRequestParameters(HttpServletRequest request) {
    Enumeration<String> paramNames = request.getParameterNames();
    while (paramNames.hasMoreElements()) {
        String paramName = paramNames.nextElement();
        String paramValue = request.getParameter(paramName);
        print("Parameter: " + paramName + " = " + paramValue);
    }
}

// Method to print headers
void logRequestHeaders(HttpServletRequest request) {
    Enumeration<String> headerNames = request.getHeaderNames();
    while (headerNames.hasMoreElements()) {
        String headerName = headerNames.nextElement();
        String headerValue = request.getHeader(headerName);
        print("Header: " + headerName + " = " + headerValue);
    }
}

// Method to print attributes
void logRequestAttributes(HttpServletRequest request) {
    Enumeration<String> attributeNames = request.getAttributeNames();
    while (attributeNames.hasMoreElements()) {
        String attributeName = attributeNames.nextElement();
        Object attributeValue = request.getAttribute(attributeName);
        print("Attribute: " + attributeName + " = " + attributeValue);
    }
}

// Method to print the request body (for POST requests)
void logRequestBody(HttpServletRequest request) throws IOException {
    BufferedReader reader = request.getReader();
    StringBuilder body = new StringBuilder();
    String line;
    while ((line = reader.readLine()) != null) {
        body.append(line);
    }
    print("Request Body: " + body.toString());
}

// Combined method to log all request details
void logFullRequest(HttpServletRequest request) throws IOException {
    print("---- Request Parameters ----");
    logRequestParameters(request);

    print("---- Request Headers ----");
    logRequestHeaders(request);

    print("---- Request Attributes ----");
    logRequestAttributes(request);

    print("---- Request Body ----");
    logRequestBody(request);
}

// Call the logFullRequest method
