  // generate unique sAMAccountName function
  public String GenerateDn(String firstname, String lastname, String mycompany, int iteration)
  {
    int MAX_USERNAME_LENGTH = 20;
    int MAX_EXT_USERNAME_LENGTH = 16;
    String generatedSAMAccountName = null;
    String generatedDn = null;

    // This will hold the final username;
    generatedSAMAccountName = firstname.substring(0, iteration) + lastname; // Première lettre du prénom + nom complet
    log.error("Rule IQera generateDn iteration : " + iteration + " et Dn égale à " + generatedDn);

    // Tronquer le nom d'utilisateur à 20 caractères maximum
    if (mycompany != "SOCIETE DE PRESTATIONS")
    {
      generatedSAMAccountName = StringUtils.substring(generatedSAMAccountName, 0, MAX_USERNAME_LENGTH);
    } else 
    {
      generatedSAMAccountName = StringUtils.substring(generatedSAMAccountName, 0, MAX_EXT_USERNAME_LENGTH)+".ext";
    }

    if (isUnique(generatedSAMAccountName)) 
    {
      // Si le nom d'utilisateur est unique, on l'utilise
      log.error("Rule IQera GenerateDn unicité : " + generatedDn);
      generatedDn ="CN=" + generatedSAMAccountName + ",OU=AD_Manager,OU=HUBEO,DC=GROUP,DC=LOCAL";
      return generatedDn;

    } else 
    {

      log.error("Rule IQera GenerateDn non unique : " + generatedDn);
      return GenerateDn(firstname, lastname, mycompany, iteration + 1); // Réappeler la fonction récursivement
    }
  }

