  public List convertEmailsToIds(List emailAddresses) {
    List identityIds = new ArrayList();
    for (String part : Util.safeIterable(emailAddresses)) {
      List idList = ObjectUtil.getIdentitiesToNotifyFromEmail(context, part.trim());
      if ( Util.nullSafeSize(idList) == 1 ) identityIds.add(idList.get(0).getName());
    }
    return ObjectUtil.convertToIds(context, Identity.class, identityIds);;
  }

