  import sailpoint.api.ObjectUtil;

  private void setApprovers(String identityName) {
    Identity id = null;
    try {
      if ( Util.isNotNullOrEmpty(identityName) ) {
        id = ObjectUtil.lockIdentityByName(context, identityName);
        // Identity id = context.getObjectByName(Identity.class, identityName);
        id.setAttribute("deputyApprover", identityName);
        id.setAttribute("alternativeApprover", identityName);
        context.saveObject(id);
        context.commitTransaction();
      }
    } catch(Exception e) {
      log.error("an error occured due to: " + e.getMessage());
    } finally {
      if ( null != id ) {
        ObjectUtil.unlockIdentity(context, id);
        context.decache(id);
      }
    }
  }




