     public static String getAuthToken() throws JSONException, ClientProtocolException, IOException, GeneralException {
    	logger.trace("Entering getAuthToken()");

    	CloseableHttpClient httpClient = HttpClientBuilder.create().build();
    	String loginURL = ARM_AUTH_BASE_URL + "/api/auth/login";

    	HttpPost tokenRequest = new HttpPost(loginURL);
    	JSONObject loginJSON = new JSONObject();
    	logger.trace("login URL : " + loginURL);
    	tokenRequest.addHeader("Content-Type", "application/json");
    	tokenRequest.addHeader("Accept", "application/json");

    	loginJSON.put("username", ARM_USERNAME);
    	loginJSON.put("password", context.decrypt(ARM_PASSWORD));
    	loginJSON.put("selectedCustomerId", ARM_CUSTOMERID);
    	loginJSON.put("isEamLogin", true);
    	loginJSON.put("fromLegacy", true);

    	StringEntity params = new StringEntity(loginJSON.toString());
      	logger.trace("login json to string : " + loginJSON.toString());
        tokenRequest.setEntity(params);

        HttpResponse loginResponse = httpClient.execute(tokenRequest);

        StatusLine loginResponseStatus = loginResponse.getStatusLine();
        int loginResponseStatusCode = loginResponseStatus.getStatusCode();
        HttpEntity loginResponseEntity = loginResponse.getEntity();        
        logger.trace("HTTP Response Code:" + loginResponseStatusCode );

        String loginResponseString = EntityUtils.toString(loginResponseEntity);
        logger.trace("loginResponseString: " + loginResponseString);

        // if not Status Okay, throw a GeneralException
        if( loginResponseStatusCode != 200 ) {
              throw new GeneralException( "Can't get ARM Authentication Token - Status: " + 
                                           String.valueOf(loginResponseStatusCode) + 
                                           " Message: " + loginResponseString );
        }

        JSONObject loginResponseObject = new JSONObject(loginResponseString);

        String authToken = (String) loginResponseObject.get("auth_token");
        String refreshToken = (String) loginResponseObject.get("refresh_token");

        logger.trace("Exiting getAuthToken()");
        return authToken;
    }

    public static JSONObject performWhatIfRealTimeAnalysis(String authToken, String customerId, String systemId, String userId, List<String> entitlementsToAddList, List<String> entitlementsToRemoveList) throws JSONException, ClientProtocolException, IOException {
    	logger.trace("Entering performWhatIfRealTimeAnalysis");

    	CloseableHttpClient httpClient = HttpClientBuilder.create().build();
    	String whatIfAnalysisUrl = ARM_PUBLIC_BASE_URL + "/api/v1/whatif/customer/" + customerId + "/erpSystem/" + systemId + "/user/" + userId + "/useranalysis";

    	HttpPost whatIfAnalysisPost = new HttpPost(whatIfAnalysisUrl);
    	JSONObject whatIfAnalysisBody = new JSONObject();

    	whatIfAnalysisPost.addHeader("Content-Type", "application/json");
    	whatIfAnalysisPost.addHeader("Accept", "application/json");
    	whatIfAnalysisPost.addHeader("Authorization", "Bearer " + authToken);

    	JSONArray entitlementsToAdd = new JSONArray();

    	int entitlementToAddArrayPosition = 0;

    	for(String sapAddRoleName : entitlementsToAddList) {

    		JSONObject entitlementToAdd = new JSONObject();
    		entitlementToAdd.put("functionalityType", "Role");
        	entitlementToAdd.put("name", sapAddRoleName);

        	entitlementsToAdd.put(entitlementToAddArrayPosition, entitlementToAdd);

        	entitlementToAddArrayPosition++;
    	}  	


    	JSONArray entitlementsToRemove = new JSONArray();

    	int entitlementToRemoveArrayPosition = 0;

      //Bug Fix: entitlements added were being passed as entitlements removed

    	for(String sapRemoveRoleName : entitlementsToRemoveList) {

    		JSONObject entitlementToRemove = new JSONObject();
    		entitlementToRemove.put("functionalityType", "Role");
    		entitlementToRemove.put("name", sapRemoveRoleName);

        	entitlementsToRemove.put(entitlementToRemoveArrayPosition, entitlementToRemove);

        	entitlementToRemoveArrayPosition++;
    	}

      //Workaround for the ARM WhatIf API issue when entitlementsToRemove has at least 1 entitlement and entitlementsToAdd is empty,
      // the ARM API errors out with a 500 Internal Server Error. So adding a dummy entitlement if that's the case
      if(entitlementsToAdd.length()<=0){
        JSONObject entitlementToAddDummy = new JSONObject();
        entitlementToAddDummy.put("functionalityType", "Role");
        entitlementToAddDummy.put("name", "SAILPOINT_DUMMY");
        entitlementsToAdd.put(0, entitlementToAddDummy);
      }

    	whatIfAnalysisBody.put("entitlementsToAdd", entitlementsToAdd);
    	whatIfAnalysisBody.put("entitlementsToRemove", entitlementsToRemove);

    	StringEntity params = new StringEntity(whatIfAnalysisBody.toString());
        logger.trace("What if real time analysis body: " + whatIfAnalysisBody.toString());
        whatIfAnalysisPost.setEntity(params);

        HttpResponse whatIfAnalysisResponse = httpClient.execute(whatIfAnalysisPost);

        StatusLine whatIfAnalysisResponseStatus = whatIfAnalysisResponse.getStatusLine();
        int whatIfAnalysisResponseStatusCode = whatIfAnalysisResponseStatus.getStatusCode();


        logger.trace("What if real time analysis response status code : " + whatIfAnalysisResponseStatusCode);
        HttpEntity whatIfAnalysisResponseEntity = whatIfAnalysisResponse.getEntity();        

        String whatIfAnalysisResponseString = EntityUtils.toString(whatIfAnalysisResponseEntity);

        // if not Status Okay, throw a GeneralException
        if( whatIfAnalysisResponseStatusCode != 200 ) {
              throw new GeneralException( "Problem executing ARM WhatIfAnalyse - Status: " + 
                                           String.valueOf(whatIfAnalysisResponseStatusCode) + 
                                           " Message: " + whatIfAnalysisResponseString );
        }

        logger.trace("What if real time analysis reponse to string : " + whatIfAnalysisResponseString);
        JSONObject whatIfAnalysisResponseJSONObject = new JSONObject(whatIfAnalysisResponseString);

        logger.trace("Exiting performWhatIfRealTimeAnalysis");
        return whatIfAnalysisResponseJSONObject;
    }

