    	 * 
    	 * The code below consistenly makes an assumption that is 'armSystemId' is not populated, this application is not
    	 * 'ARM-aware' and therefore should not be part of any risk analysis against ARM
    	 */
    	HashMap sapRoleNameRequestsBySystemId = new HashMap();

		ArrayList sapRoleRequestsForOneSystem =new ArrayList();

		ArrayList sapRolesToAddForOneSystem = new ArrayList();
		sapRoleRequestsForOneSystem.add(0, sapRolesToAddForOneSystem);

		ArrayList sapRolesToRemoveForOneSystem = new ArrayList();
		sapRoleRequestsForOneSystem.add(1, sapRolesToRemoveForOneSystem);


    	for(HashMap requestItemMap : requestedItems) {

    		String requestType = requestItemMap.get("accessType");
    		if(requestType.equalsIgnoreCase("Entitlement")) {

    			QueryOptions managedAttributeQuery = new QueryOptions();
    			managedAttributeQuery.addFilter(Filter.eq("id", requestItemMap.get("id")));
    			logger.trace("Searching for entitlement with this id - " + requestItemMap.get("id"));
    			Iterator maIterator = context.search(ManagedAttribute.class, managedAttributeQuery,"application.armSystemId,value");
    			logger.trace("after addition item id query");
    			if(maIterator != null) {

    				Object[] returnedObject = (Object[]) maIterator.next();

    				String armSystemId = (String) returnedObject[0];
    				if(armSystemId != null) {

    					//ArrayList sapRoleRequestsForOneSystem;
    					//ArrayList sapRolesToAddForOneSystem;
    					if(sapRoleNameRequestsBySystemId.get(armSystemId)==null) {
    						//sapRoleRequestsForOneSystem = new ArrayList();
    						//sapRolesToAddForOneSystem= new ArrayList();
    						//sapRoleRequestsForOneSystem.add(0, sapRolesToAddForOneSystem);
    						sapRoleNameRequestsBySystemId.put(armSystemId, sapRoleRequestsForOneSystem);
    					} else { //if array list for this system id already exists we can assume that the add list in position 0 
    						//already exists because of above code block
    						sapRoleRequestsForOneSystem = (ArrayList) sapRoleNameRequestsBySystemId.get(armSystemId);
    						sapRolesToAddForOneSystem = (ArrayList) sapRoleRequestsForOneSystem.get(0);
    					}
    					String sapRoleName = (String) returnedObject[1];
    					sapRolesToAddForOneSystem.add(sapRoleName);
    				}
    				Util.flushIterator(maIterator);
    			}
    		}  		    		
    	}

    	logger.trace("sap role names to add by system id : " + sapRoleNameRequestsBySystemId.toString());

    	for(HashMap requestRemoveItemMap : requestedRemoveItems) {

    		String requestType = requestRemoveItemMap.get("accessType");
    		if(requestType.equalsIgnoreCase("Entitlement")) {
    			QueryOptions managedAttributeQuery = new QueryOptions();
    			managedAttributeQuery.addFilter(Filter.eq("id", requestRemoveItemMap.get("id")));
    			logger.trace("querying for this id of removal item - " + requestRemoveItemMap.get("id"));
    			Iterator maIterator = context.search(ManagedAttribute.class, managedAttributeQuery,"application.armSystemId,value");
    			logger.trace("After removal item id query");
    			if(maIterator != null) {

    				Object[] returnedObject = (Object[]) maIterator.next();

    				String armSystemId = (String) returnedObject[0];
    				if(armSystemId != null) {

    					//ArrayList sapRoleRequestsForOneSystem;
    					//ArrayList sapRolesToRemoveForOneSystem;
    					if(sapRoleNameRequestsBySystemId.get(armSystemId)==null) {
    						//sapRoleRequestsForOneSystem = new ArrayList();
    						//sapRolesToRemoveForOneSystem= new ArrayList();
    						//sapRoleRequestsForOneSystem.add(1, sapRolesToRemoveForOneSystem);
    						sapRoleNameRequestsBySystemId.put(armSystemId, sapRoleRequestsForOneSystem);
    					} else {
    						sapRoleRequestsForOneSystem = (ArrayList) sapRoleNameRequestsBySystemId.get(armSystemId);
    						//If size is two then we already have both a role add and role remove list added
    						//therefore just append to existing remove roles list
    						if(sapRoleRequestsForOneSystem.size()==2) {
    							sapRolesToRemoveForOneSystem = (ArrayList) sapRoleRequestsForOneSystem.get(1);
    						} else { //else we have one entry we need to create the role remove list, 
    							//if we had 0 entries the return for this system id would have been null and hit earlier if statement
    							sapRolesToRemoveForOneSystem = new ArrayList();
        						sapRoleRequestsForOneSystem.add(1, sapRolesToRemoveForOneSystem);
    						}
    					}
    					String sapRoleName = (String) returnedObject[1];
    					sapRolesToRemoveForOneSystem.add(sapRoleName);
    				}
    				Util.flushIterator(maIterator);
    			}
    		}

    	}
    	//For each selected identity perform a risk analysis based off requested add/remove roles
    	for(String identityName : selectedIdentityNames){

    		/*
    		 * Iterate over all system id keys in the sapRoleNameRequestsBySystemId map
    		 * for each system id, search for that Application and get the account links for that system for that user
    		 * Perform requests against ARM using that link's native identity + system id
    		 * If no link is returned for that user then make a call to a different API that does an ARM analysis without a user id
    		 */

    		Set roleRequestsSet = sapRoleNameRequestsBySystemId.keySet();

    		Iterator keyIterator = roleRequestsSet.iterator();

    		while(keyIterator.hasNext()) {
    			String armSystemId = (String) keyIterator.next();

    			QueryOptions systemIdQuery = new QueryOptions();
    			systemIdQuery.addFilter(Filter.eq("application.armSystemId", armSystemId));
    			logger.trace("Arm system id from key iterator : " + armSystemId);
    			systemIdQuery.addFilter(Filter.eq("identity.name", identityName));
    			logger.trace("Before querying for the links user has on the system");
    			Iterator linksOnArmSystem = context.search(Link.class, systemIdQuery, "nativeIdentity,application.name");
        		logger.trace("After querying for links user has on system");
    			if(linksOnArmSystem == null || !linksOnArmSystem.hasNext()) {
    				//No link returned, this means we need to make an ARM what if analysis API call without a userID
    				logger.trace("No links on arm system, perform new user what if analysis");
    				ArrayList roleRequests = (ArrayList) sapRoleNameRequestsBySystemId.get(armSystemId);
            		ArrayList sapRoleNamesToAdd = (ArrayList) roleRequests.get(0);

            		ArrayList sapRoleNamesToRemove;

            		if(roleRequests.size()==2) {
            			sapRoleNamesToRemove = (ArrayList) roleRequests.get(1);
            		}

            		Application sapSystem = context.getUniqueObject(Application.class, Filter.eq("armSystemId", armSystemId));

            		if(sapRoleNamesToAdd != null || sapRoleNamesToRemove != null) {
            			String sapSystemName = "ARM SAP System";

            			if(sapSystem != null){
            				sapSystemName = sapSystem.getName();
            			}

                		JSONObject whatIfResponseJSON = performWhatIfRealTimeNewUserAnalysis(authToken, ARM_CUSTOMERID, armSystemId, sapRoleNamesToAdd, sapRoleNamesToRemove);
                    	String whatIfBackGroundJobId = performWhatIfBackgroundNewUserAnalysis(authToken, ARM_CUSTOMERID, armSystemId, sapRoleNamesToAdd, sapRoleNamesToRemove);

                    	logger.trace("What if response : " + whatIfResponseJSON.toString());
                    	JSONArray violations = null;
                    	//Because response is a JSONObject when it is null, check for it to be null before casting as array
                    	if(whatIfResponseJSON.get("violations") != null){
                    		logger.trace("what is this? " + whatIfResponseJSON.get("violations").getClass());
                    		violations = (JSONArray) whatIfResponseJSON.get("violations");
                    	}


                    	if(violations != null && violations.length()>0) {
                    		validationStrings.add("Risks were found on your request against the " + sapSystemName + " system.  Click the following link to view detailed results : ");
                    		validationStrings.add(ARM_REPORT_URL + whatIfBackGroundJobId);
                    		for(int i =0; i<violations.length(); i++) {
                    			JSONObject violation = (JSONObject) violations.get(i);

                    			String riskName = violation.getString("riskName");          									
                    			String riskLevel = violation.getString("riskLevel");                   					
                    			String riskType = violation.getString("riskType");

								//riskCode value is null if the user is a super user; the null check is needed
								String riskCode = (!violation.isNull("riskCode"))?violation.getString("riskCode"):"";
								//String riskCode = violation.getString("riskCode");

                    			String riskDescription = violation.getString("riskDescription");


                    			validationStrings.add("Risk Code : " + riskCode);
                    			validationStrings.add("Risk Name : " + riskName);	
                    			validationStrings.add("Risk Level : " + riskLevel);
                    			validationStrings.add("Risk Type : " + riskType);
                    			validationStrings.add("Risk Description : " + riskDescription);
                    			JSONArray activities = violation.getJSONArray("activities");

                    			if(activities != null){
                    				validationStrings.add("Activities : ");
                    				for(int j=0; j<activities.length(); j++) {
                    					JSONObject activity = (JSONObject) activities.get(j);
                    					String functionCode = activity.getString("functionCode");
                    					String functionDescription = activity.getString("functionDescription");
                    					String functionName = activity.getString("functionName");
                    					validationStrings.add("Function Name : " + functionName);
                    					validationStrings.add("Function Code : " + functionCode);
                    					validationStrings.add("Function Description : " + functionDescription);
                    				}						
                    			}

                    		}

                    	}                  

            		}

    			} else {

    				while(linksOnArmSystem.hasNext()) {

            			ArrayList roleRequests = (ArrayList) sapRoleNameRequestsBySystemId.get(armSystemId);
            			ArrayList sapRoleNamesToAdd = (ArrayList) roleRequests.get(0);

            			ArrayList sapRoleNamesToRemove;

            			if(roleRequests.size()==2) {
            				sapRoleNamesToRemove = (ArrayList) roleRequests.get(1);
            			}

            			Object[] linkArray = (Object[]) linksOnArmSystem.next();	
            			if(sapRoleNamesToAdd != null || sapRoleNamesToRemove != null) {
            				String sapUserName = (String) linkArray[0];
            				String sapSystemName = (String) linkArray[1];
            				logger.trace("Perform what if real time and background analysis");

            				logger.debug("About to Call Out to ARM");
            				logger.debug("Auth Token: " + authToken );
            				logger.debug("ARM CustomerId" + ARM_CUSTOMERID );
            				logger.debug("ARM SystemId: " + armSystemId );
            				logger.debug("SAP Username: " + sapUserName );
            				logger.debug("SAP RoleNames To Add: " + Util.listToCsv(sapRoleNamesToAdd));
            				logger.debug("SAP RoleNames To Remove: "  + Util.listToCsv(sapRoleNamesToRemove) );


                			JSONObject whatIfResponseJSON = performWhatIfRealTimeAnalysis(authToken, ARM_CUSTOMERID, armSystemId, sapUserName, sapRoleNamesToAdd, sapRoleNamesToRemove);

                			logger.debug("Result of performWhatIfRealTimeAnalysis:" + whatIfResponseJSON.toString() );

                    		String whatIfBackGroundJobId =  performWhatIfBackgroundAnalysis(authToken, ARM_CUSTOMERID, armSystemId, sapUserName, sapRoleNamesToAdd, sapRoleNamesToRemove);
                			logger.debug("Result of performWhatIfBackgroundAnalysis: " + whatIfBackGroundJobId );

                    		logger.trace("What if response : " + whatIfResponseJSON.toString());
                    		//JSONArray violations = (JSONArray) whatIfResponseJSON.get("violations");
							JSONArray violations = null;
							//Because response is a JSONObject when it is null, check for it to be null before casting as array
							if(whatIfResponseJSON.get("violations") != null){
								logger.trace("what is this? " + whatIfResponseJSON.get("violations").getClass());
								violations = (JSONArray) whatIfResponseJSON.get("violations");
							}

                    		if(violations != null && violations.length()>0) {
                    			validationStrings.add("Risks were found on your request against the " + sapSystemName + " system for the " + sapUserName + " account.  Click the following link to view detailed results : ");
                    			validationStrings.add(ARM_REPORT_URL + whatIfBackGroundJobId);
                    			for(int i =0; i<violations.length(); i++) {
                    				JSONObject violation = (JSONObject) violations.get(i);
                    				String riskName = violation.getString("riskName");

                    				String riskLevel = violation.getString("riskLevel");

                    				String riskType = violation.getString("riskType");

							//riskCode value is null if the user is a super user; the null check is needed
							String riskCode = (!violation.isNull("riskCode"))?violation.getString("riskCode"):"";
							//String riskCode = violation.getString("riskCode");

                    				String riskDescription = violation.getString("riskDescription");


                    				validationStrings.add("Risk Code : " + riskCode);
                    				validationStrings.add("Risk Name : " + riskName);	
                    				validationStrings.add("Risk Level : " + riskLevel);
                    				validationStrings.add("Risk Type : " + riskType);
                    				validationStrings.add("Risk Description : " + riskDescription);
                    				JSONArray activities = violation.getJSONArray("activities");

                    				if(activities != null){
                    					validationStrings.add("Activities : ");
                    					for(int j=0; j<activities.length(); j++) {
                    						JSONObject activity = (JSONObject) activities.get(j);
                    						String functionCode = activity.getString("functionCode");
                    						String functionDescription = activity.getString("functionDescription");
                    						String functionName = activity.getString("functionName");
                    						validationStrings.add("Function Name : " + functionName);
                    						validationStrings.add("Function Code : " + functionCode);
                    						validationStrings.add("Function Description : " + functionDescription);
                    					}						
                    				}

                    			}

                    		}
                    	}		

            		}
    				Util.flushIterator(linksOnArmSystem);
    			}  			

    		}	

    	} 	

    	return validationStrings;

import java.util.Map;
import java.util.HashMap;
import java.util.StringJoiner;

import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;

import com.google.gson.Gson;

import sailpoint.tools.GeneralException;

// Parse the access token from the response JSON
private static String parseBearerToken(String response) {
  String tokenPrefix = "\"access_token\":\"";
  int tokenStart = response.indexOf(tokenPrefix) + tokenPrefix.length();
  int tokenEnd = response.indexOf("\"", tokenStart);
  return response.substring(tokenStart, tokenEnd);
}

try {

  String clientId = "YOUR_CLIENT_ID";
  String clientSecret = "YOUR_CLIENT_SECRET";
  String tenantId = "YOUR_TENANT_ID";
  String tokenUrl = "https://login.microsoftonline.com/" + tenantId + "/oauth2/v2.0/token";

  String body = new StringJoiner("&")
    .add("grant_type=client_credentials")
    .add("client_id=" + clientId)
    .add("client_secret=" + clientSecret)
    .add("scope=https://graph.microsoft.com/.default")
    .toString();

  HttpRequest tokenRequest = HttpRequest.newBuilder()
    .uri(URI.create(tokenUrl))
    .header("Content-Type", "application/x-www-form-urlencoded")
    .POST(HttpRequest.BodyPublishers.ofString(body))
    .build();

  HttpClient client = HttpClient.newHttpClient();
  HttpResponse<String> tokenResponse = client.send(tokenRequest, HttpResponse.BodyHandlers.ofString());

  if (tokenResponse.statusCode() == 200) {

    String accessToken = parseBearerToken(response.body());
    String graphUrl = "https://graph.microsoft.com/v1.0/users";

    String password = "";
    String displayName = "";
    String mailNickname = "";
    String userPrincipalName = "";

    Map payload = new HashMap();
    payload.put("accountEnabled", true);
    payload.put("displayName", displayName);
    payload.put("mailNickname", mailNickname);
    payload.put("userPrincipalName", userPrincipalName);
    Map passwordProfile = new HashMap();
    passwordProfile.put("forceChangePasswordNextSignIn", false);
    passwordProfile.put("password", password);
    payload.put("passwordProfile", passwordProfile);

    Gson gson = new Gson();
    String jsonPayload = gson.toJson(payload);

    // Create a POST request to create a user
    HttpRequest request = HttpRequest.newBuilder()
      .uri(URI.create(graphUrl))
      .header("Authorization", "Bearer " + accessToken)
      .header("Content-Type", "application/json")
      .POST(HttpRequest.BodyPublishers.ofString(jsonPayload))
      .build();

   // HttpClient client = HttpClient.newHttpClient();
    HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());

    if (response.statusCode() == 201) {
      System.out.println("User created successfully: " + response.body());
    } else {
      System.out.println("Error: " + response.statusCode());
      System.out.println("Response Body: " + response.body());
    }
  }

} catch (GeneralException e) {
  throw new GeneralException("GeneralException occured when try to connect microsift graph api." + e.getMessage());
}


