  import java.net.HttpURLConnection;
  import java.net.URL;
  import java.io.OutputStream;
  import java.io.InputStreamReader;
  import java.io.BufferedReader;

  String username = "1038";
  String password = "admin";
  String url = "https://graph.microsoft.com/v1.0/users";

  URL endpointUrl = new URL(url);
  HttpURLConnection connection = (HttpURLConnection) endpointUrl.openConnection();

  connection.setRequestMethod("POST");
  connection.setRequestProperty("Content-Type", "application/json");
  connection.setRequestProperty("Authorization", "Basic " + java.util.Base64.getEncoder().encodeToString((username + ":" + password).getBytes()));
  connection.setDoOutput(true);

  Map payload = new HashMap();
  payload.put("accountEnabled", true);
  payload.put("displayName", "Adele Vance");
  payload.put("mailNickname", "AdeleV");
  payload.put("userPrincipalName", "AdeleV@contoso.com");

  Map passwordProfile = new HashMap();
  passwordProfile.put("forceChangePasswordNextSignIn", true);
  passwordProfile.put("password", "xWwvJ]6NMw+bWH-d");

  payload.put("passwordProfile", passwordProfile);

  Gson gson = new Gson();
  String jsonPayload = gson.toJson(payload);

  OutputStream os = connection.getOutputStream();
  os.write(jsonPayload.getBytes("UTF-8"));
  os.flush();
  os.close();

  int responseCode = connection.getResponseCode();
  BufferedReader in = new BufferedReader(new InputStreamReader(connection.getInputStream()));
  String inputLine;
  StringBuffer response = new StringBuffer();

  while ((inputLine = in.readLine()) != null) {
    response.append(inputLine);
  }
  in.close();

  log.error("responseCode " + responseCode);
  log.error("response: " + response.toString());

  // Log the response from the API call
  if (responseCode == HttpURLConnection.HTTP_OK) {
    log.error("Workflow launched successfully: " + response.toString());
  } else {
    log.error("Failed to launch workflow. Response code: " + responseCode);
    log.error("Error response: " + response.toString());
  }

  return response.toString();


