  /**
  *Needed for Versant
   * Method to get custom object Map based on name
   * @param customObjectName
   * @return customObjectMap
   */
  public Map getMap(String customObjectName) {

    logger.info("Started getMap : "+customObjectName);

    return getCustomObjectMap(customObjectName);

  }

  /**
   * Takes the name of a custom object and returns the contents in the form of a map.
   * Basically, this just gets the parent map contained within the Attributes entry
   * of the specified custom object.
   * @param customObjectName
   * @return customObjMap
   */
  public Map getCustomObjectMap(String customObjectName) {

    logger.info("Started getCustomObjectMap..."+customObjectName);

    Map customObjMap = new HashMap();
    try{
      if(Util.isNotNullOrEmpty(customObjectName)) {
        Custom cust = context.getObject(Custom.class, customObjectName);
        if(null != cust) {
          customObjMap = cust.getAttributes().getMap();
          context.decache(cust);
        }
        else {
          throw new Exception("Unable to get an IIQ custom object named " + customObjectName);
        }
      }
      else {
        throw new Exception("customObjectName is invalid. customObjectName = " + customObjectName);
      }
    }
    catch(Exception e){
      logger.error("Exception in getting custom object map",e);
      throw e;
    }
    return customObjMap;
  }


  /**
     * create the confirmation form
     * @param displayForm - the form filled by the requester
     * @param formModel - contains key-value pair
     * @return Confirmation Form object
     */
  public Form getConfirmationForm(String displayFormName, String useCaseName, Map formModel) {
    logger.debug("Started Method : getConfirmationForm");
    Form confirmationForm = null;
    List displayFormFields = null;
    String displayName = null;
    String name = null;
    String type = null;
    String displayType = null;
    int span = 1;
    boolean isMulti;
    Form displayForm =context.getObjectByName(Form.class,displayFormName);

    confirmationForm = new Form();
    Section confirmationFormSection = new Section();
    confirmationFormSection.setColumns(2);
    confirmationForm.setTitle("Confirmation Form");
    List formSectionNames = new ArrayList();

    for(int i=0; i<=10; i++){
      Form.Section secName = displayForm.getSection(i);
      if(null!=secName){
        formSectionNames.add(secName.getName());
      }else{
        break;
      }
    }
    Map buttons = new HashMap();
    buttons.put("Back","back");
    buttons.put("Cancel","cancel");
    buttons.put("Confirm","next");

    useCaseName = useCaseName + " Review";
    confirmationFormSection.setLabel(useCaseName);
    for(String section:formSectionNames) {
      displayFormFields = displayForm.getSection(section).getFields();
      if(displayFormFields!=null) {
        for (Field displayFormField : displayFormFields) {
          if(formModel.get(displayFormField.getName())!=null){
            Field confirmationFormField = new Field();
            displayName = displayFormField.getDisplayName();
            name = displayFormField.getName();
            type = displayFormField.getType();
            displayType = displayFormField.getDisplayType();
            span = displayFormField.getColumnSpan();
            isMulti = displayFormField.isMulti();
            if(isMulti) {
              confirmationFormField.setMulti(isMulti);
            }
            confirmationFormField.setType(type);
            confirmationFormField.setDisplayName(displayName);
            confirmationFormField.setName(name);
            confirmationFormField.setColumnSpan(span);
            confirmationFormField.setDisplayType(displayType);
            confirmationFormField.setReadOnly(true);
            confirmationFormSection.add(confirmationFormField);
          }
        }
      }
    }
    for (Map.Entry entry : buttons.entrySet()) {
      Button button = new Button(entry.getKey(),entry.getValue());
      confirmationForm.add(button);
    }
    confirmationForm.add(confirmationFormSection);
    logger.debug("Method Exit : getConfirmationForm");
    return confirmationForm;
  }



  /*
   * Method to display Submit/Cancellation Message for the request.
   */
  public void displayMessage(String infoMessage) {

    logger.info("Started displayMessage");

    HttpSession httpSession = null;

    try{
      if(CustomGlobal.get("UserSession")!=null){
        httpSession= (HttpSession)CustomGlobal.get("UserSession");
        if(httpSession!=null){
          if (debugEnabled) {
            logger.debug("Requester's Session is not null");
          }
          if (debugEnabled) {
            logger.debug("Requester's Session is working...............");
          }
          FacesMessage myMessage = new FacesMessage(FacesMessage.SEVERITY_INFO, infoMessage, "This is ignored");
          List<FacesMessage> myMessages = new ArrayList<FacesMessage>();
          myMessages.add(myMessage);
          // Overwrite current message list
          httpSession.setAttribute("sailpoint.web.PageCodeBase.sessionMessages", myMessages);
          if (debugEnabled) {
            logger.debug("End of displayMessage");
          }
        }
        else{
          if (debugEnabled) {
            logger.debug("Requester's Session is Null");
          }
        }
        CustomGlobal.remove("UserSession");
      }
      else{
        if (debugEnabled) {
          logger.debug("CustomGlobal Object is Null");
        }
      }
    }
    catch(Exception e){
      logger.error("Exception in display message",e);
      throw e;
    }
    logger.info("Method Exit: displayMessage");
  }

  /**

                * Launch workflow Subprocess

                *@param wfArguments - workflow Subprocess input Variables

                **/

  public void initiateWorkflow(String launchWfName, Map wfArguments){

    logger.debug("Starting method initiateWorkflow");
    System.out.println("launchWfName ::::; "+launchWfName);
    System.out.println("wfArguments ::::; "+wfArguments);
    if(null != wfArguments){

      WorkflowLaunch wfLaunch = new WorkflowLaunch();

      if(null != launchWfName){

        Workflow wf = context.getObjectByName(Workflow.class, launchWfName);
        System.out.println("wf ::::; "+wf);
        if(null != wf){
          Workflower workflower = new Workflower(context);
          String identityName = wfArguments.get("identityName");
          String updatedLaunchWfName = Util.isNotNullOrEmpty(identityName)? (String) launchWfName+ " - "+identityName: (String)launchWfName;
          logger.debug("Launching the workflow "+updatedLaunchWfName);
          System.out.println("Launching the workflow "+updatedLaunchWfName);
          WorkflowLaunch launch = workflower.launchSafely(wf, updatedLaunchWfName, wfArguments);
        }
      }
    }
    logger.debug("Ending method initiateWorkflow");
  }



  /**
  *needed for versant
   * Method to initialize formModel
   * @param workflow - workflow
   * @param operation - match operation from custom object ex. create, edit
   * @param useCase - Attribute Name
   * @return formModel
   */
  public HashMap initializeModelForOperation(Workflow workflow, String operation, String useCase) {

    logger.info("Started initialize formModel : "+useCase);


    Map formModel = new HashMap();
    if(workflow.get("requesterName")!=null)
      formModel.put("requester", workflow.get("requesterName"));
    else
      formModel.put("requester", workflow.get("requester"));
    formModel.put("timeZone",workflow.get("httpSession").getAttribute("timeZone").getID());
    formModel.put("transformerClass", "sailpoint.transformer.IdentityTransformer");
    formModel.put("transformerOptions", "sailpoint.transformer.IdentityTransformerOptions");
    formModel.put("operation", operation);
    formModel.put("useCase", useCase);
    // formModel.put("customVSNTWrapperConfigMap", workflow.get("customVSNTWrapperConfigMap") );
    // formModel.put("customVSNTWrapperForms", workflow.get("customVSNTWrapperForms") );

    logger.info("Method Exit: initializeModelForOperation");


    return formModel;
  }


  //Returns a list of applications to be selected for functional accounts
  public List getApplicationList() {

    logger.info("started getApplicationList : ");

    List applicationList = new ArrayList();
    String value = null;
    //return application list from custom file and attach the id as well so we can search with both
    try{
      Map map = getMap(Application_Custom_Object);
      Map objectMap = map.get("SnowAppDetails");
      for (Map.Entry entry : objectMap.entrySet())  {
        value = (String) entry.getValue();
        applicationList.add(value.concat(" ("+entry.getKey()+")"));

      }

    }catch (Exception e) {
      logger.error("Exception in getAppicationList",e);
      throw e;
    }
    logger.info("Method Exit: getAppicationList");

    return applicationList;
  }


