  public boolean checkEmailExists(String email){
    logger.info("started checkEmailExists : "+email);

    QueryOptions qo = new QueryOptions();
    qo.addFilter(Filter.and(Filter.eq("email", email)));
    qo.addFilter(Filter.and(Filter.eq("inactive", false)));
    Iterator iter  = context.search(Identity.class,qo);
    if (iter.hasNext())  {
      logger.info("end method : checkEmailExists true");

      return true;
    }
    logger.info("end method : checkEmailExists false");

    return false;

  }


