  private boolean isMemberExistInWG(String workgroupName, String identityNameOrId) {
    if ( Util.isNotNullOrEmpty(workgroupName) && Util.isNotNullOrEmpty(identityNameOrId) ) {
      Identity identity = context.getObject(Identity.class, identityNameOrId);
      if ( identity == null ) {
        throw new IllegalArgumentException("Identity not found with " + identityNameOrId); 
      }
      Filter filter = Filter.and(Filter.eq("workgroups.name", workgroupName), Filter.eq("id", identity.getId()));
      QueryOptions qo = new QueryOptions();
      qo.add(filter);
      qo.setResultLimit(1);
      return context.countObjects(Identity.class, qo) > 0 ? true : false;
    }
    return false;
  }

  private void addMembersToWorkGroup(String workGroupName, String identityName) {
    if (Util.isNotNullOrEmpty(workGroupName) && Util.isNotNullOrEmpty(identityName)) {
      Identity workGroup = context.getObject(Identity.class, workGroupName);
      if ( null != workGroup && workGroup.isWorkgroup()) {
        Identity memberIdentity = context.getObject(Identity.class, identityName);
        if ( memberIdentity != null ) memberIdentity.add(workGroup);
        context.saveObject(memberIdentity);
        context.commitTransaction();
      }
    }
  }

  private void removeMembersFromWorkGroup(String workGroupName, String identityName) {
    if (Util.isNotNullOrEmpty(workGroupName) && Util.isNotNullOrEmpty(identityName)) {
      Identity workGroup = context.getObject(Identity.class, workGroupName);
      if ( null != workGroup && workGroup.isWorkgroup()) {
        Identity memberIdentity = context.getObject(Identity.class, identityName);
        if ( memberIdentity != null ) memberIdentity.remove(workGroup);
        context.saveObject(memberIdentity);
        context.commitTransaction();
      }
    }
  }

  private List getWorkGroupMembers(Sring workgroupName) {
    List existingMembersList = new ArrayList();
    if ( Util.isNotNullOrEmpty(workgroupName) ) {
      Identity workGroup = context.getObjectByName(Identity.class, workgroupName);
      Iterator itr = ObjectUtil.getWorkgroupMembers(context, workGroup, null);
      while (null != itr && itr.hasNext()) {
        Object[] object = (Object[]) itr.next();
        if ( null != object ) {
          Identity memberIdentity = (Identity) object[0];
          existingMembersList.add(memberIdentity.getId());
        }
      }
    }
    return existingMembersList;
  }

  /*
  *
  * Main Code Start Here.
  *
  */

  String appName = null;

  if (void != domain && Util.isNotNullOrEmpty(domain) ) {
    Custom custom = context.getObjectByName(Custom.class, "Custom-GroupMappings");
    Map domainMap = custom.get(domain);
    appName = domainMap.get("appName");
  }

  Filter maFilter = Filter.and(Filter.eq("application.name", appName), Filter.eq("displayName", ddname));
  ManagedAttribute ma = context.getUniqueObject(ManagedAttribute.class, maFilter);

  ma.setDisplayName(ddname);

  Pattern pattern = Pattern.compile("GL(\\d{2})");
  Matcher matcher = pattern.matcher(glevel);
  if (matcher.find()) {
    String number = matcher.group(1); // Extract the number part (01, 02, etc.)
    int num = Integer.parseInt(number);  // Convert "01" to "1", "02" to "2"
    String glvl = "GL" + num;
    ma.setAttribute("governanceLevel", glvl);
  }

  String suffix = " approval required";
  if (glevel.contains(suffix)) {
    glevel = glevel.substring(0, glevel.length() - suffix.length());
  }
  if (glevel.contains("GL00")) {
    glevel = "GL00 - Auto";
  }

  ma.setAttribute("manualOverride", mover);
  ma.setAttribute("approvalMode", glevel);
  ma.setAttribute("description", edsc);

  Identity idn = context.getObject(Identity.class, aname);

  if ( idn != null ) {
    ma.setOwner(idn);
  }

  String AZURE_APP_NAME = "Azure Active Directory";
  String entBusinessApprover = ma.getAttribute("entBusApprovers");

  if (!Util.nullSafeCaseInsensitiveEq(esource, AZURE_APP_NAME)) {
    ddname = ename.split(",")[0].split("CN=")[1];     
  }

  if ((Util.isNullOrEmpty(entBusinessApprover) || Util.isNotNullOrEmpty(entBusinessApprover)) && Util.isNotNullOrEmpty(ddname)) {
    String workgroupName = "WG-Approver-" + ddname;
    Identity workgroupIdentity = context.getObjectByName(Identity.class, workgroupName);
    if ( workgroupIdentity == null ) {
      workgroupIdentity = new Identity();
      workgroupIdentity.setName(workgroupName);
      workgroupIdentity.setWorkgroup(true);
      context.saveObject(workgroupIdentity);
    }      
    workflow.put("wgrp", workgroupName);
    entBusinessApprover = workgroupName;
    ma.setAttribute("entBusApprovers", entBusinessApprover);
  }

  List newMembersList = new ArrayList(adeo);
  List existingMembersList = getWorkGroupMembers(entBusinessApprover);

  List updatedMembersList = new ArrayList(newMembersList);
  updatedMembersList.removeAll(existingMembersList);

  List removeableMembersList = new ArrayList(newMembersList);
  removeableMembersList.removeAll(updatedMembersList);

  List updatedRemoveAbleMembersList = new ArrayList(existingMembersList);
  updatedRemoveAbleMembersList.removeAll(removeableMembersList);

  // add members to workgroup
  if ( Util.nullSafeSize(updatedMembersList) > 0 ) {
    for ( String identityName : updatedMembersList ) {
      if (!isMemberExistInWG(entBusinessApprover, identityName)) {
        addMembersToWorkGroup(entBusinessApprover, identityName);
      }
    }
  }

  // remove members from workgroup
  if ( Util.nullSafeSize(updatedRemoveAbleMembersList) > 0 ) {
    for ( String identityName : updatedRemoveAbleMembersList ) {
      if (isMemberExistInWG(entBusinessApprover, identityName)) {
        removeMembersFromWorkGroup(entBusinessApprover, identityName);
      }
    }
  } else if (Util.isNotNullOrEmpty(glevel) && (glevel.contains("GL00") || glevel.contains("GL01"))) { // remove members from workgroup when governance level is GL00 or GL01
    if ( Util.nullSafeSize(removeableMembersList) > 0 ) {
      for ( String identityName : removeableMembersList ) {
        if (isMemberExistInWG(entBusinessApprover, identityName)) {
          removeMembersFromWorkGroup(entBusinessApprover, identityName);
        }
      }
    }
  }

  // add an entitlement owner to workgroup
  addMembersToWorkGroup(entBusinessApprover, aname);

  if ( existingMembersList.contains(aname) ) {
    removeMembersFromWorkGroup(entBusinessApprover, aname);
  }

  context.saveObject(ma);
  context.commitTransaction();






