  private void cleanWorkgroupMembers(List<String> adeo, String operation, String approverName) throws GeneralException {
    if (Util.nullSafeSize(adeo) > 0 && operation != null) {
      if ( null != approverName ) adeo.add(approverName);
      for ( String owner : Util.safeIterable(adeo)) {
        if (owner != null) {
          Identity identity = context.getObject(Identity.class, owner);
          if (identity != null) {
            if (Util.isNotNullOrEmpty(entBusinessApprover)) {
              Identity workGroup = context.getObjectByName(Identity.class, entBusinessApprover);
              log.error("workGroup---- " + workGroup);
              if (workGroup != null && Util.nullSafeCaseInsensitiveEq(operation, "Remove")) {
                log.error("entered into Remove Workgroup members block....");
                Iterator itr = ObjectUtil.getWorkgroupMembers(context, workGroup, null);
                while (null != itr && itr.hasNext()) {
                  Object[] object = (Object[]) itr.next();
                  if ( null != object ) {
                    Identity memberIdentity = (Identity) object[0];
                    memberIdentity.remove(workGroup);
                    context.saveObject(memberIdentity);
                  }
                }
              }
              if (workGroup != null && Util.nullSafeCaseInsensitiveEq(operation, "Add")) {

                log.error("entered into Add Workgroup members block....");

                identity.add(workGroup); // adding new member into workgroup
                context.saveObject(identity);
              }
            }
          }
        }
      }
    }
  }

  return isMemberExistInWG("WG-Approver-TEST IIQ Group", "1038");





