  import java.util.ArrayList;
  import java.util.List;
  import java.util.regex.Matcher;
  import java.util.regex.Pattern;

  import sailpoint.object.Application;
  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.ManagedAttribute;

  import sailpoint.tools.Util;

  Application app = context.getObjectByName(Application.class, appname);

  Filter maFilter = Filter.and(Filter.eq("application.name", appname), Filter.eq("displayName", ddname));
  ManagedAttribute ma = context.getUniqueObject(ManagedAttribute.class, maFilter);

  ma.setDisplayName(ddname);

  Pattern pattern = Pattern.compile("GL(\\d{2})");
  Matcher matcher = pattern.matcher(glevel);

  if (matcher.find()) {
    // Extract the number part (01, 02, etc.)
    String number = matcher.group(1);
    // Convert "01" to "1", "02" to "2"
    int num = Integer.parseInt(number);
    String glvl = "GL" + num;
    ma.setAttribute("governanceLevel", glvl);
  }
  String suffix = " approval required";
  if (glevel.contains(suffix)) {
    glevel = glevel.substring(0, glevel.length() - suffix.length());
  }

  if (glevel.contains("GL00")) {
    glevel = "GL00 - Auto";
  }

  ma.setAttribute("manualOverride", mover);
  ma.setAttribute("approvalMode", glevel);

  Identity idn = context.getObject(Identity.class, aname);
  ma.setOwner(idn);

  String entBusinessApprover = ma.getAttribute("entBusApprovers");
  Identity approversWorkGroup = context.getObjectByName(Identity.class, entBusinessApprover);

  if (Util.nullSafeSize(adeo) > 0) {
    for ( String owner : Util.safeIterable(adeo)) {
      if ((owner != null)) {
        Identity identity = context.getObject(Identity.class, owner);
        if (identity != null) {
          if (Util.isNotNullOrEmpty(workgroupName)) {
            Identity workGroup = context.getObjectByName(Identity.class, workgroupName);
            Iterator itr = ObjectUtil.getWorkgroupMembers(context, workGroup, Arrays.asList("name"));
            while (null != itr && itr.hasNext()) {
              String memberName = itr.next()[0];
              if ( null != memberName ) {
                Identity memberIdentity = context.getObjectByName(Identity.class, memberName);
                memberIdentity.remove(workGroup);
                context.saveObject(memberIdentity);
              }
            }
            // adding new member into workgroup
            identity.add(workGroup);
            context.saveObject(identity);
            // context.commitTransaction();
          }
        }
      }
    }
  }

  log.error("Final ManagedAttribute (Entitlement) XML:: " + ma.toXml());

  context.saveObject(ma);
  context.commitTransaction();





