  // Helper methods adapted for BeanShell
  static void addDynamicField(Section section, String key, Object value) {
    Field field = new Field();
    field.setName(key);
    field.setDisplayName(convertToDisplayName(key));

    field.setDisplayType(Field.TYPE_STRING);
    field.setValue(value != null ? value.toString() : "");

    // Make standard fields read-only
    if (isStandardField(key)) {
      field.setReadOnly(true);
    }
    section.add(field);
  }



  static void addDecisionField(Section section, int sectionNum) {
    Field decision = new Field();
    decision.setName("decision_" + sectionNum);
    decision.setDisplayName("Decision");
    decision.setDisplayType(Field.DISPLAY_TYPE_RADIO);
    decision.setRequired(true);

    List options = new ArrayList();
    options.add("Approve");
    options.add("Deny");
    decision.setAllowedValues(options);

    section.add(decision);

  }



  static boolean isStandardField(String fieldName) {
    return fieldName.matches("(?i)application|type|value|displayName|owner|property");
  }

  static String convertToDisplayName(String key) {
    return key.replaceAll("([A-Z])", " $1")
      .replaceAll("_", " ")
      .trim()
      .replaceAll("\\s+", " ");
  }

  static void addFormControls(Form form) {
    form.clearButtons();
    Button cancel = new Button("back", "Cancel");
    Button submit = new Button("next", "Submit");
    form.add(cancel);
    form.add(submit);
  }



