  private static String getIdentityRequestApprovalStatus(SailPointContext context, String identityRequestName) throws GeneralException {

    String identityRequestApprovalStatus = null;
    if (identityRequestName == null) {
      throw new GeneralException("GeneralException occured due to identityRequestName is " + identityRequestName);
    }
    IdentityRequest idReq = ObjectUtil.transactionLockByName(context, IdentityRequest.class, identityRequestName);
    try {
      List<ApprovalSummary> approvalSummaries = idReq.getApprovalSummaries();
      if (Util.nullSafeSize(approvalSummaries) > 0) {
        ApprovalSummary approvalSummary = approvalSummaries.get(0);
        if (null != approvalSummary) {
          ApprovalSet approvalSet = approvalSummary.getApprovalSet();
          if (null != approvalSet) {
            List<ApprovalItem> items = approvalSet.getItems();
            if (Util.nullSafeSize(items) > 0) {
              ApprovalItem approvalItem = items.get(0);
              if (null != approvalItem) {
                State state = approvalItem.getState();
                identityRequestApprovalStatus = state != null ? state.toString() : null;
              }
            }
          }	
        }
      }
    } catch (Exception e) {
      throw new GeneralException("An Exception occured due to " + e.getMessage());
    }
    return identityRequestApprovalStatus;
  }

