 Log logger = LogFactory.getLog("rule.macquarie.PolicyViolation_Allow_Until_Prepone_Rule");

 private void sendEmailNotification(SailPointContext context, Map templateArgs, String templateName, List emailDestination) {
   logger.trace("Entered method sendEmailNotification()");
   if (Util.isNullOrEmpty(templateName)) {
     throw new IllegalArgumentException("Email Template Name cannot be null or empty");
   }

   EmailTemplate template = (EmailTemplate) context.getObject(EmailTemplate.class, templateName);
   if (template == null) {
     throw new GeneralException("Email Template was not found: " + templateName);
   }
   logger.debug("Loaded email template: " + templateName);
   logger.debug("Will send emails to users: " + emailDestination);

   EmailOptions options = new EmailOptions(emailDestination, templateArgs);
   options.setSendImmediate(true);
   options.setNoRetry(true);

   try {
     context.sendEmailNotification(template, options);
   } catch (RetryableEmailException e) {
     logger.error("RetryableEmailException:", e);
     logger.error(e.getMessage());
   } catch (EmailException e) {
     logger.error(e);
     throw new GeneralException(e);
   } catch (GeneralException e) {
     logger.error(e);
     throw new GeneralException(e);
   }
   logger.trace("Email sent.");
   logger.trace("Exiting method sendEmailNotification()");
 }

 /**
* Retrieves the Mitigation Expiration ID for a given Policy Violation ID from the database.
*
* This method executes a SQL query to find the Mitigation Expiration ID associated with the
* provided Policy Violation ID. It logs the query execution and any exceptions that may occur
* during the process.
*
* @param policyViolationId The Policy Violation ID to search for in the mitigation expiration data.
* @return The Mitigation Expiration ID associated with the given Policy Violation ID, or null
*         if no matching records are found or an error occurs during the query execution.
*
* @throws IllegalArgumentException if the provided policyViolationId is null or empty.
*/
 private String getMitigationExpirationId(String policyViolationId) {
   logger.trace("Entered method getMitigationExpirationId()");
   if (Util.isNullOrEmpty(policyViolationId)) {
     throw new IllegalArgumentException("Policy Violation ID cannot be null or empty");
   }

   String mitigationExpId = null;
   logger.debug("Policy Violation ID is: " + policyViolationId);

   // Prepare SQL and arguments
   Map arguments = new HashMap();
   arguments.put("policyViolationId", policyViolationId);
   String sqlQuery = "sql:SELECT id FROM identityiq.spt_mitigation_expiration " +
     "WHERE ExtractValue(certifiable_descriptor, '//CertifiableDescriptor//PolicyViolation/@id') = :policyViolationId";

   try {
     logger.debug("Executing SQL query to retrieve Mitigation Expiration ID: " + sqlQuery);
     Iterator<String> itr = context.search(sqlQuery, arguments, null);

     if (itr == null) {
       logger.warn("Search returned null iterator for query: " + sqlQuery);
     }

     while (itr != null && itr.hasNext()) {
       String me = itr.next();
       if (Util.isNotNullOrEmpty(me)) {
         mitigationExpId = me;
         logger.debug("Mitigation Expiration ID found: " + mitigationExpId);
       }
     }
   } catch (GeneralException e) {
     logger.error("Error occurred while executing SQL query or processing results for Policy Violation ID: " + policyViolationId + " Error Message: " + e.getMessage());
   }
   logger.trace("Exiting method getMitigationExpirationId() with result: " + mitigationExpId);

   return mitigationExpId;
 }

 /**
* Processes Identity History Items to update Mitigation Expiration dates for Policy Violations.
*
* This method executes a query to retrieve Identity History Items where the mitigation expiration
* date exceeds a year from the decision date, and updates their Mitigation Expiration dates and
* associated Mitigation Expiration objects in the system.
*
* @throws Exception If any errors occur during the database query, object retrieval, or saving.
*/
 public void processMitigationExpirationUpdates() throws GeneralException {
   logger.trace("Entered method processMitigationExpirationUpdates()");
   String sqlQuery = "sql:SELECT id FROM identityiq.spt_identity_history_item " +
     "WHERE DATEDIFF(FROM_UNIXTIME(ExtractValue(action, '//CertificationAction/@mitigationExpiration') / 1000), " +
     "FROM_UNIXTIME(ExtractValue(action, '//CertificationAction/@decisionDate') / 1000)) >= 365 " +
     "AND status = 'Mitigated' AND certification_type = 'PolicyViolation'";

   Iterator<String> it = null;
   try {
     logger.debug("Executing SQL query to retrieve Identity History Items: " + sqlQuery);
     it = context.search(sqlQuery, null, null);
   } catch (GeneralException e) {
     logger.error("Error executing SQL query: " + sqlQuery + " Error Message: " + e.getMessage());
     throw new GeneralException("Error executing SQL query" + " Error Message: " + e.getMessage());
   }

   // Process each Identity History Item
   while (it != null && it.hasNext()) {
     String iHistItemId = it.next();

     logger.debug("Processing Identity History Item with ID: " + iHistItemId);

     try {
       IdentityHistoryItem iHistoryItem = context.getObjectById(IdentityHistoryItem.class, iHistItemId);
       CertificationAction certAction = iHistoryItem.getAction();

       logger.trace("Retrieving CertificationAction details " + certAction.toXml());

       Date decisionDate = certAction.getDecisionDate();
       logger.trace("Decision Date: " + decisionDate);

       Date mitigationExpiration = certAction.getMitigationExpiration();
       logger.trace("Mitigation Expiration: " + mitigationExpiration);

       Identity actor = certAction.getActor(context);
       logger.trace("Actor: " + actor.getName());

       Identity historyIdentity = iHistoryItem.getIdentity();
       logger.trace("Identity: " + historyIdentity.getName());

       // Increment the mitigation expiration date by 365 days
       Date incrementDateByDays = Util.incrementDateByDays(decisionDate, 365);
       iHistoryItem.getAction().setMitigationExpiration(incrementDateByDays);

       String identityHistoryComments = iHistoryItem.getComments();
       iHistoryItem.setComments(identityHistoryComments + "\n" + " SYSTEM UPDATED Mitigation Expiration Date this " + mitigationExpiration + " to " + incrementDateByDays);

       context.saveObject(iHistoryItem);

       String policyViolationId = iHistoryItem.getPolicyViolation().getId();
       String meId = getMitigationExpirationId(policyViolationId);

       if (Util.isNotNullOrEmpty(meId)) {
         MitigationExpiration me = context.getObjectById(MitigationExpiration.class, meId);
         me.setExpiration(incrementDateByDays);
         String meComments = me.getComments();
         me.setComments(meComments + "\n" + " SYSTEM UPDATED Mitigation Expiration Date this " + mitigationExpiration + " to " + incrementDateByDays);

         context.saveObject(me);
         logger.debug("Updated Mitigation Expiration for Policy Violation ID: " + policyViolationId);
       }

       ArrayList emailDestination = new ArrayList();

       emailDestination.add(actor.getEmail());
       emailDestination.add(historyIdentity.getEmail());

       // Examples of adding arguments to an email template if needed for an email template.
       Map templateArgs = new HashMap();

       templateArgs.put("policyViolationId", policyViolationId);
       templateArgs.put("mitigationExpiration", mitigationExpiration);
       templateArgs.put("incrementDateByDays", incrementDateByDays);
       templateArgs.put("recipient", actor.getName() + ", " + historyIdentity.getName());

       sendEmailNotification(context, templateArgs, "Policy Violation Prepone Email Template", emailDestination);

     } catch (Exception e) {
       logger.error("Error processing Identity History Item with ID: " + iHistItemId + " Error Message: " + e.getMessage());
     }
   }

   try {
     context.commitTransaction();
     logger.info("Transaction committed successfully.");
   } catch (GeneralException e) {
     logger.error("Error committing transaction" + " Error Message: " + e.getMessage());
     throw new GeneralException("Error committing transaction" + " Error Message: " + e.getMessage());
   }
   logger.trace("Exiting method processMitigationExpirationUpdates()");
 }

 processMitigationExpirationUpdates();




 return "END";


