       } elseif ($strTypeOfNonHumanAcc -ieq "Resource" -and $strSubType -ieq "MeetingRoom") {

         Write-ToLog "INFO" "Entered into Resource mailbox block...."

         #New-Mailbox -Room -Name $name -DisplayName $displayName -Alias $displayName -PrimarySmtpAddress $userPrincipalName

         Write-ToLog "INFO" "Room mailbox created successfully for user: $userPrincipalName"
       }
     } else {
         Write-ToLog "INFO" "Skipped mailbox creation: Type/SubType do not match expected combinations."
     }

 }
 catch {
     Write-ToLog "ERROR" "Error occurred: $_"
 }
 finally {
     try {
         #Disconnect-ExchangeOnline -Confirm:$false
         Write-ToLog "INFO" "Disconnected from Exchange Online."
     }
     catch {
         Write-ToLog "ERROR" "Error during disconnect: $_"
     }

     Write-ToLog "INFO" "PowerShell script ended."
 }

