  customObj.setAttributes(new Attributes(customMap));
  context.saveObject(customObj);
  context.commitTransaction();

  System.out.println(" Custom Object 'Employee_CustomData1' created/updated successfully.");
} catch (Exception e) {

  System.out.println("Error: " + e.getMessage());
}

