import java.text.SimpleDateFormat;
import java.util.Date;
import sailpoint.object.Identity;
import sailpoint.tools.Util;

try {

  // New identity (joiner)
  if (previousIdentity == null && newIdentity != null) {
    String deputyApprover = newIdentity.getAttribute("deputyApprover");
    String alternativeApprover = newIdentity.getAttribute("alternativeApprover");
    Object hireDateObj = newIdentity.getAttribute("hireDate");

    log.error("deputyApprover " + deputyApprover);
    log.error("alternativeApprover " + alternativeApprover);
    log.error("hireDateObj " + hireDateObj);
    log.error("newIdentity XML: " + newIdentity.toXml());

    // Check if either deputyApprover OR alternativeApprover is missing
    boolean anyAttributeMissing = Util.isNullOrEmpty(deputyApprover) || Util.isNullOrEmpty(alternativeApprover);

    log.error("anyAttributeMissing: " + anyAttributeMissing);

    // If both attributes are present, don't trigger
    if (!anyAttributeMissing) {
      return false;
    }

    // Check if hireDate exists
    if (hireDateObj == null) {
      return false;  // Can't determine eligibility without hire date
    }

    // Parse hire date
    Date hireDate = null;
    if (hireDateObj instanceof Date) {
      hireDate = (Date)hireDateObj;
    } else {
      try {
        String hireDateStr = hireDateObj.toString();
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd");
        hireDate = sdf.parse(hireDateStr);
      } catch (Exception e) {
        return false;  // Can't parse date
      }
    }

    Date today = new Date();

    // Ensure correct order for date difference calculation
    int daysDifference = 0;
    if (hireDate.before(today) || hireDate.equals(today)) {
      daysDifference = Util.getDaysDifference(hireDate, today);
    } else {
      // Future hire date - should not trigger
      return false;
    }

    log.error("daysDifference: " + daysDifference);

    // EXPLICIT check - must be AT LEAST 21 days (>= 21)
    boolean hiredLongEnough = daysDifference >= 21;

    log.error("hiredLongEnough: " + hiredLongEnough);

    // Only trigger if hire date is old enough
    return hiredLongEnough;
  }

  else if (previousIdentity != null && newIdentity != null) {    // Existing identity (mover)
    String newDeputyApprover = newIdentity.getAttribute("deputyApprover");
    String newAlternativeApprover = newIdentity.getAttribute("alternativeApprover");

    log.error("newDeputyApprover " + newDeputyApprover);
    log.error("newAlternativeApprover " + newAlternativeApprover);
    log.error("newIdentity XML: " + newIdentity.toXml());
    log.error("previousIdentity XML: " + previousIdentity.toXml());

    // Trigger if EITHER deputyApprover OR alternativeApprover is missing in the new state
    return Util.isNullOrEmpty(newDeputyApprover) || Util.isNullOrEmpty(newAlternativeApprover);
  }


  // Default case (leaver or any other case)
  return false;
} catch (Exception e) {
  // Log error and don't trigger if there's an exception
  return false;
}

