// Helper Methods
public Approval buildApproval(ApprovalSet approvalSet, String approver, String targetIdentityName, String approvalType) {
  Approval approval = new Approval();
  approval.setApprovalSet(approvalSet);
  approval.addArg("workItemTargetClass", "sailpoint.object.Identity");
  approval.setOwner((String) approver);
  approval.setState(State.Pending);
  approval.setDescription(approvalType + " Approval - Account Changes for User: " + targetIdentityName);
  approval.addArg("workItemNotificationTemplate", "LCM Identity Update Approval");
  approval.addArg("workItemTargetName", targetIdentityName);
  return approval;
}

public ApprovalSet getFilteredApprovalSet(ApprovalSet approvalSet, String itemName) {
  ApprovalSet itemApprovalSet = null;
  if ( approvalSet != null @and itemName != null ) {
    List items = approvalSet.getItems();
    if (items != null) {
      for (ApprovalItem item : items) {
        if ( null != item @and item.getName().equalsIgnoreCase(itemName)) {
          itemApprovalSet = new ApprovalSet();
          ApprovalItem itemCopy = (ApprovalItem) XMLObjectFactory.getInstance().clone(item, context);
          itemCopy.setState(null);
          itemApprovalSet.add(itemCopy);
        }
      }
    }
  }
  return itemApprovalSet;
}

public Approval buildExchangeRetentionApprover(ApprovalSet approvalSet, List retentionApproverList, String targetIdentityName, String approvalType) {
  if(retentionApproverList !=null @and retentionApproverList.size() > 0) {
    List parallelApprovalList = new ArrayList();
    for (String ownerName : retentionApproverList) {
      approval = new Workflow.Approval();
      if (ownerName != null) {
        approval.setOwner("\"" + ownerName + "\"");
      }
      ApprovalSet set = new ApprovalSet();
      set.add(item);
      approval.setMode("parallel");
      approval.setApprovalSet(getFilteredApprovalSet(approvalSet, "groups"));
      approval.addArg("workItemTargetClass", "sailpoint.object.Identity");
      approval.addArg("workItemTargetName", identityName);
      approval.setDescription(approvalType + " Approval - Account Changes for User: " + targetIdentityName);
      parallelApprovalList.add(approval);
    }
    Approval finalParallelApproval = new Approval();
    finalParallelApproval.setMode("any");
    finalParallelApproval.setChildren(parallelApprovalList);
    return finalParallelApproval;
  }
  return null;
}

public String getEntDataOwner(SailPointContext context, ApprovalItem item) {
  String entOwner = "";
  String name = item.getName();
  Object val = item.getValue();
  String application = item.getApplication();
  String lVal = "";
  if (val instanceof String){
    lVal = (String)val;
  } else if (val instanceof List){
    if (((List)val).size() > 1){
      log.warn("Has more than one item. ");
    }
    lVal = val.get(0);
  }
  QueryOptions qo = new QueryOptions();
  Filter f1 = Filter.eq("attribute", name);
  Filter f2 = Filter.eq("value", lVal);
  Filter f3 = Filter.eq("application.name", application);
  qo.addFilter(f1);
  qo.addFilter(f2);
  qo.addFilter(f3);
  List mas = context.getObjects(ManagedAttribute.class, qo);
  if (mas != null && mas.size() > 0){
    log.trace("Get the first. ");
    ManagedAttribute ma = mas.get(0);
    entOwner = ma.getOwner() != null ? ma.getOwner().getName() : null;
  }
  context.decache();
  return entOwner;
}

