public String getOrCreateWorkgroupForApprovers(List approvers, String appIdentifier) {

  SimpleDateFormat format = new SimpleDateFormat("yyyyMMdd_hhmmssmmm");
  Date now = new Date();
  String tempDate = format.format(now);
  String wgName = "ExchangeSharedMailbox_WG_" + appIdentifier;
  Identity wg = context.getObjectByName(Identity.class, wgName);
  if (wg == null) {
    log.error("Create new workgroup: " + wgName);
    wg = new Identity();
    wg.setName(wgName);
    wg.setWorkgroup(true);
    wg.setNotificationOption(Identity.WorkgroupNotificationOption.MembersOnly);
    context.saveObject(wg);
    context.commitTransaction();
  } else {
    log.error("Found existing workgroup: " + wgName);
  }
  Identity approverIdentity;
  for (String aiName : approvers) {
    log.error("Get approverIdentity: " + aiName);
    approverIdentity = context.getObjectByName(Identity.class, aiName);
    if (approverIdentity != null) {
      log.error("Add wg, " + wgName + ", to approverIdentity, " + aiName + ", and save.");
      approverIdentity.add(wg);
      context.saveObject(approverIdentity);
      context.commitTransaction();
    }
  }
  return wgName;
}

Object getObjectAttribute(Class className, Filter filter, String attrName) {
  Iterator itr = null;
  try {
    QueryOptions qo = new QueryOptions();
    qo.addFilter(filter);
    itr = context.search(className, qo, attrName);
    if(itr.hasNext()) return (itr.next()[0]);
  }
  catch (Exception e) {
  }
  finally{
    Util.flushIterator(itr);
  }
  return null;
}

public String getAppIdentifier(String appIdentifier) {
  log.error("Entered inot getAppIdentifier");
  log.error("appIdentifier--> " + appIdentifier);
  String workgroupName = "";
  if (null != appIdentifier) {
    appIdentifier = appIdentifier.substring(0,3);
    String appEditor1;
    String appEditor2;
    int i = 0;
    String appManager = com.bny.sii.idip.IDIPService.getInstance(context).getAppMetadata(appIdentifier).getAppManager();

    if (null != appManager) i += 1;
    appEditor1 = com.bny.sii.idip.IDIPService.getInstance(context).getAppMetadata(appIdentifier).getAttribute("appRoles").get("APP EDITOR 1");

    if (null != appEditor1) i += 1;
    appEditor2 = com.bny.sii.idip.IDIPService.getInstance(context).getAppMetadata(appIdentifier).getAttribute("appRoles").get("APP EDITOR 2");

    if (null != appEditor2) i += 1;

    if (i == 0) {
      return "spadmin";
    } else if (i == 1) {
      if (null != appManager)
        return appManager;
      else if (null != appEditor1)
        return appEditor1;
        else if (null != appEditor2)
        return appEditor2;
        } else if (i > 1) {
      List appApprovers = new ArrayList();
      if (null != appManager) appApprovers.add(appManager);
      if (null != appEditor1) appApprovers.add(appEditor1);
      if (null != appEditor2) appApprovers.add(appEditor2);

      workgroupName = getOrCreateWorkgroupForApprovers(appApprovers, appIdentifier);
    }
  }
  return workgroupName;
}
