public String getDataOwnerName(ApprovalSet approvalSet) {
  String dataOwner = "";
  List items = approvalSet.getItems();
  if (items != null) {
    for (ApprovalItem item : items) {
      if ( item != null @and item.getName().equalsIgnoreCase("LOB")) {
        dataOwner = getEntDataOwner(context, item);
      }
    }
  }
  return dataOwner;
}

