List names = new ArrayList();
QueryOptions ops = new QueryOptions();
ops.add(Filter.eq("inactive", true));
Iterator identityNames = context.search(Identity.class, ops, "name");
while (identityNames.hasNext()) {
    Object[] result = (Object[])identityNames.next();
    String identityName = (String)result[0];
    Identity identity = context.getObjectByName(Identity.class, identityName);
    if (identity != null) {
        boolean isPrivileged = false;
        List<Link> links = identity.getLinks();
        if (links != null) {
            for (Link link : links) {
                if (link.getAttributes().getBoolean("privileged")) {
                    isPrivileged = true;
                    break;
                }
            }
        }

        if (isPrivileged) {
            names.add(identityName);
        }
    }
}

return names;


