	  /**
	  *  The SuccessFactors ODATA API requires picklist id for doing insert/update operation.
	  *  These codes can be figured out from the SucessFactors instance by following below steps:
	  *   a> Login into your SuccessFactors instance.
	  *   b> Search for "Picklists Management" in search bar and select Export
	  *       all picklist(s) radio button.
	  *   c> Click on Submit button.
	  *   d> Wait for few minutes, until the download button gets enabled.
	  *
	  *  In the below example the codes are considered for Business Phone
	  *  and Business Email mapped to ecPhoneType and ecEmailType
	  *  respectively as per SuccessFactors default Picklists values
	  *  The service account should have the proper minimum privilege for performing the update operations.
	  *
	  *  NOTE: The order in which below attributes namely username, business email and business phone are updated should not
	  *  be altered i.e. update order should be username, business email and business phone.
	  */

	  /**
	  * ecEmailType for Business Email.
	  */
	  String BUSINESS_PHONE_TYPE = "10605";

	  /**
	  * ecPhoneType for Business Phone.
	  */
	  String BUSINESS_EMAIL_TYPE = "8448";

	  ProvisioningResult result = new ProvisioningResult();
	  result.setStatus(ProvisioningResult.STATUS_COMMITTED);
	  boolean isPrimary = true;
	  Map map = new HashMap();

	  /**
	  * This method would provision a given business phone, business email and username.
	  */
	  public void doProvision() throws Exception {
	  String accNativeIdentity = request.getNativeIdentity();

	  //Get handle of the implementation object.
	  SuccessFactorsConnectorImpl sfObj = connector.getImplObject();

	  if (Util.isEmpty(provisionMap)) {
	     throw new Exception("Empty provisionMap detected");
	  }
	  try {
	      //updating username
	      if (null != provisionMap.get(SuccessFactorsConstants.ATTR_USERNAME)) {
	         sfObj.provisionUsername(accNativeIdentity,
	         provisionMap.get(SuccessFactorsConstants.ATTR_USERNAME), map);
	      }

	     //updating business email
	     if (null != provisionMap.get(SuccessFactorsConstants.ATTR_PRIMARY_EMAIL_ADDRESS)) {
	        sfObj.provisionEmail(accNativeIdentity, isPrimary,
	        provisionMap.get(SuccessFactorsConstants.ATTR_PRIMARY_EMAIL_ADDRESS),
	        BUSINESS_EMAIL_TYPE, map);
	     }

	    //updating business phone
	    if (null != provisionMap.get(SuccessFactorsConstants.UPDATEPHONE)) {
	       sfObj.provisionPhone(accNativeIdentity, isPrimary,
	       provisionMap.get(SuccessFactorsConstants.UPDATEPHONE), BUSINESS_PHONE_TYPE, map);
	    }
	  } catch (Exception e) {
	      log.error("Exception during provisioning ", e);
	      throw e;
	    }
	  }
	  doProvision();
	  return result;

