     map.put("MCF_IMUSERID",networkIDValue);
}else{
     if(log.isDebugEnabled()){
          log.debug("No NetworkID exist for user:"+ identity );
     }
   }
 statement.close();
 resultSet.close();

 //Return the map of which contains the final resource object map with the new field value.
 return map;

