import com.google.gson.Gson;
import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import com.google.gson.JsonParser;
import sailpoint.tools.Util;

//In case of Dropbox, Dropbox V2 REST APIs for team membership response contains two elements, 
//namely "cursor" and "has_more", along with other elements. The "cursor" is an encrypted token 
//which represents the next page to be fetched, if any, and will form part of the subsequent API calls. 
//Whereas, "has_more" is a boolean value which explicitly indicates whether more records are 
//available for fetching.
//
//This After Rule stores the "cursor" and "has_more" values, from the response, in a map named 
//'transientValues' in the Application object. This map will store the necessary information which 
//will be used by the BEFORE RULE	to manipulate the next API call.
//
//Please note that the flag indicating whether the managed system contains more records is stored 
//by the key named "hasMore". This field is MANDATORY as it will the deciding factor for aborting the pagination requests.

Gson gson = new Gson();
JsonObject jsonObject = JsonParser.parseString(rawResponseObject).getAsJsonObject();
String cursor = jsonObject.get("cursor").getAsString();
boolean hasMore = jsonObject.get("has_more").getAsBoolean();

if(Util.isNotNullOrEmpty(cursor)) {
  Map transientValues = application.getAttributeValue("transientValues");
  if(transientValues == null) {
    transientValues = new HashMap();
    application.setAttribute("transientValues", transientValues);
  }
  transientValues.put("cursor", cursor);
  transientValues.put("hasMore", hasMore);
}


