import com.google.gson.Gson;
import sailpoint.tools.Util;

//In case of Dropbox V2, the 'cursor' returned from the previous team membership listing API is expected to be stored 
//in a map named 'transientValues' in the application by the Web Service After Rule.
//
//When the cursor value exists, the REST API url is modified to direct to the paging API and the cursor is sent 
//as part of the form data.
//
//Please note that the flag "hasMore" must be already from by the earlier reuqest's AFTER RULE as this field is MANDATORY 
//and acts as the deciding factor for aborting the pagination requests. If "hasMore" is not set or is set to FALSE, 
//the pagination request will be terminated.

Map obj = (Map) application.getAttributeValue("transientValues");
if(null != obj) {
  String cursor = obj.get("cursor");
  if(Util.isNotNullOrEmpty(cursor)) {
    Map postBodyMap = (Map) requestEndPoint.getBody();
    postBodyMap.put("jsonBody", "{\"cursor\":\"" + cursor + "\"}");
    requestEndPoint.setFullUrl(requestEndPoint.getFullUrl() + "/continue");
  }
}
return requestEndPoint;


