import connector.common.JsonUtil;
import java.util.Map;

//Please note that the flag "hasMore" must be already from by the earlier request's AFTER RULE as this field is MANDATORY
//and acts as the deciding factor for aborting the pagination requests. If "hasMore" is not set or is set to FALSE,
//the pagination request will be terminated except for first time..

Map transientValues = application.getAttributeValue("transientValues");
//here we check whether it is a first request or not and if yes,
//then it will execute without searchAfter parameter

if(transientValues != null ) {
//If it is not a first request, then it will check for the search after value(s) updated in transientValues map in after operation rule.
//It will update the searchAfter parameter with value in request body.
log.debug("Before Rule: transientValues-->"+JsonUtil.render(transientValues));
Map body = requestEndPoint.getBody();
String jsonBody = (String) body.get("jsonBody");
Map jsonMap = JsonUtil.toMap(jsonBody);
jsonMap.put("searchAfter", transientValues.get("searchAfterArray"));
String finalBody = JsonUtil.render(jsonMap);
body.put("jsonBody", finalBody);
log.debug("Before Rule: Request Body-->"+jsonMap);
requestEndPoint.setBody(body);
}
return requestEndPoint;


import java.util.Map;

//expected number of objects from the pagination result.
Integer expectedRecordsCount = 250;

//check if processedResponseObject is null or empty, then no need to process
if (processedResponseObject!= null && !processedResponseObject.isEmpty()) {
//Fetch the last object to get the updated value of the searchAfter parameter.
Map lastRecord = processedResponseObject.get(processedResponseObject.size()-1);

//Attribute value on which sorting works, this attribute value will be used in searchAfter parameter.
String id = (String)lastRecord.get("id");
String[] searchAfterArray= new String[]{id};
log.debug("AFTER RULE: searchAfterArray ==> " + id);

Integer fetchedRecordsCount = 0;
if(null != processedResponseObject) {
fetchedRecordsCount  = ((List) processedResponseObject).size();
}

//If the fetched records are equal to the expected number of records, the hasMore value will be set to TRUE and paging will continue.
boolean hasMore = (fetchedRecordsCount != 0 && null != expectedRecordsCount && fetchedRecordsCount.equals(expectedRecordsCount));
log.debug("AFTER RULE: Has More? ==> " + hasMore);

Map transientValues = application.getAttributeValue("transientValues");
if(transientValues == null) {
transientValues = new HashMap();
application.setAttribute("transientValues", transientValues);
}
transientValues.put("hasMore", hasMore);
if(hasMore){
transientValues.put("searchAfterArray", searchAfterArray);
}
}


import sailpoint.object.Application;
import sailpoint.object.Link;
import sailpoint.tools.Util;
import java.util.List;

if (link != null && link.getApplication() != null) {
    String sAMAccountName = link.getAttribute("sAMAccountName");
    String distinguishedName = link.getAttribute("distinguishedName");
    List settings = link.getApplication().getAttributeValue("domainSettings");

    if (settings != null && Util.isNotNullOrEmpty(sAMAccountName) && Util.isNotNullOrEmpty(distinguishedName)) {

        for (Map settingObj : Util.iterate(settings)) {

            if (!Util.isEmpty(settingObj)) {
                String domainNetBiosName = Util.getString(settingObj, "domainNetBiosName");
                String domainDN = Util.getString(settingObj, "domainDN");

                if (Util.isNotNullOrEmpty(domainNetBiosName) &&
                    Util.isNotNullOrEmpty(domainDN) &&
                    distinguishedName.toLowerCase().endsWith(domainDN.toLowerCase())) {

                    value = domainNetBiosName + "\\" + sAMAccountName;
                }
            }
        }
    }
}

return value;

