List result = new ArrayList();

// Check requester identity attribute.
if (requester != null) {
  String department = requester.getAttribute("Department");
  // first param dictates whether a comment is required or not
  // in this case it is false and an comment is not required
  result.add(new AccessRequestConfigDTO(false, "Comment required for " + department));
}

// Use the requesteeRequiresComment extended attribute to see if a comment is required
for (Identity requestee : requestees) {
    if (new Boolean(requestee.getAttribute("requesteeRequiresComment"))) {
        if (action.equals("add")) {
            result.add(new AccessRequestConfigDTO(true, "Comment required for requestee to add access item."));
        }
        else if (action.equals("remove")) {
            result.add(new AccessRequestConfigDTO(true, "Comment required for requestee to remove access item."));
        }
    }
}

// Check requestItem attribute to see if it has requiresComment enabled
if (requestedItem != null) {
    boolean required = false;
    if (requestedItem instanceof ManagedAttribute) {
        required = new Boolean(((ManagedAttribute)requestedItem).getAttribute("requiresComment"));
    } else if (requestedItem instanceof Bundle) {
        required = new Boolean(((Bundle)requestedItem).getAttribute("requiresComment"));
    }

    if (required) {
        // in this case the required param is dynamic and depends on the extended attribute requiresAttachment
        result.add(new AccessRequestConfigDTO(required, "Comment required for requested item."));
    }
}

return result;

