import sailpoint.object.*;
import java.util.*;
import sailpoint.service.*;
import sailpoint.tools.Util;
import sailpoint.web.modeler.RoleUtil;
import sailpoint.api.ManagedAttributer;
import sailpoint.tools.xml.XMLObjectFactory;

// Result is always a list of AccessRequestConfigDTOs. The list may be empty but shouldn't be null.
List result = new ArrayList();

// attachments based on extendedAttribute on Bundle
if (requestee != null) {
    if (requestedItem != null && requestedItem instanceof Bundle) {
        Bundle requestedBundle = (Bundle)requestedItem;
        List bundles = new ArrayList();
        bundles.add(requestedBundle);
        bundles.addAll(requestedBundle.getRequirements());
        bundles.addAll(requestedBundle.getInheritance());
        for (Bundle bundle : bundles) {
            boolean requiresAttachment = Util.otob(bundle.getAttribute("requiresAttachment"));
            if (requiresAttachment) {
                result.add(new AccessRequestConfigDTO(true, "Role request requires an attachment."));
            }
        }
    }
}

// attachments based on extendedAttribute on ManagedAttribute in Bundle
if (requestee != null) {
    if (requestedItem != null && requestedItem instanceof Bundle) {

        Map managedAttrBundleMap = new HashMap();

        Bundle requestedBundle = (Bundle)requestedItem;
        // put all the bundles in a Set so we auto-filter out duplicates
        Set bundles = new HashSet();
        bundles.add(requestedBundle);
        bundles.addAll(requestedBundle.getRequirements());
        bundles.addAll(requestedBundle.getInheritance());
        for (Bundle bundle : bundles) {

            // For each bundle, find all of the managed attributes. If any MAs match our conditions, put the MA in a map
            // linking it back to the contributing Bundle(s)

            // Finding out what entitlement a role has is way less direct than it sounds
            List entitlements = RoleUtil.getAllSimpleEntitlements(bundle, context, null, null, requester);

            // iterate through the List and inspect each Map for an application/property/value match
            for (Map entitlementMap : entitlements) {
                String entApp = (String) entitlementMap.get("applicationName");
                String entProp = (String) entitlementMap.get("property");
                String entValue = (String) entitlementMap.get("value");
                Application app = context.getObjectByName(Application.class, entApp);
                String entAppId = app.getId();

                // let's make sure all three of these aren't null before fetching the MA (otherwise could get false positives)
                if (Util.isNotNullOrEmpty(entApp) && Util.isNotNullOrEmpty(entProp) && Util.isNotNullOrEmpty(entValue) && Util.isNotNullOrEmpty(entAppId)) {
                    ManagedAttribute ma = ManagedAttributer.get(context, entAppId, entProp, entValue);
                    if (ma != null) {
                        String extAttrBundleMA = ma.getAttribute("entitleAuth");
                        if (extAttrBundleMA != null && Util.nullSafeEq(extAttrBundleMA, "High")) {
                            Set mapBundles = (Set)managedAttrBundleMap.get(ma);
                            if (mapBundles == null) {
                                mapBundles = new HashSet();
                                managedAttrBundleMap.put(ma, mapBundles);
                            }
                            mapBundles.add(bundle);
                        }
                    }
                }
            }
        }

        // use the map we built to build the attachment configs, being able to still directly reference the bundle and contributing managed attribute
        if (log.isDebugEnabled()) {
            log.debug("Final MA-Bundle Map: " + XMLObjectFactory.getInstance().toXml(managedAttrBundleMap));
        }
        for (ManagedAttribute maKey : managedAttrBundleMap.keySet()) {
            Set mapBundles = managedAttrBundleMap.get(maKey);
            StringBuilder buff = new StringBuilder();
            for (Bundle mapBundle : mapBundles) {
                buff.append(mapBundle).append(", ");
            }
            buff.delete(buff.length() - 2, buff.length());
            result.add(new AccessRequestConfigDTO(true, "Bundle(s) " + buff.toString() + " with MA " + maKey + " with extendedAttr needs to show this message."));
        }
    }
}

return result;


 import sailpoint.object.ProvisioningProject;
 import sailpoint.object.ProvisioningPlan.AccountRequest;
 import sailpoint.object.ProvisioningPlan.AttributeRequest;
 import sailpoint.tools.Util;
 import sailpoint.object.Attributes;
 import sailpoint.connector.SAPConnector;
 import java.util.ArrayList;
 import sailpoint.workflow.SAPGRCIntegrationLibrary;
 import sailpoint.api.SailPointContext;

 private String SUNRISE_DATE = "addDate";
 private String SUNSET_DATE = "removeDate";
 private String GRCDELIMITER = "grcDelimiter";
 private String GRCRequestDateFormatString = "yyyy-MM-dd";

 /**
  * Method to get dates from Map
  * @param roleDates Map containing dates assigned to Business role.
  * @param busiRoleExpansion Map containing a list of business roles per entitlement.
  * @param entitlementName Name of entitlement being provisioned.
  * @return Map of sunrise and sunset dates.
  */
 private Map getDates (Map roleDates, Map busiRoleExpansion, String entitlementName) {
      Map datesFetched = new HashMap();
      List businessRoles = (List) busiRoleExpansion.get(entitlementName);
      if (!Util.isEmpty(businessRoles)) {
          /*
           * Two business roles with common entitlement and different dates
           * are not send for SOD check so busiRoleExpansion will contain same dates
           * for common entitlement hence we are fetching 0th element of businessRoles.
           */
          String businessRole = (String) businessRoles.get(0);
          Date sunriseDate = (Date) roleDates.get(businessRole + SUNRISE_DATE);
          Date sunsetDate = (Date) roleDates.get(businessRole + SUNSET_DATE);
          datesFetched.put(SUNRISE_DATE,sunriseDate);
          datesFetched.put(SUNSET_DATE,sunsetDate);
      }
      return datesFetched;
    }

try {

    SAPGRCIntegrationLibrary sapgrc = new SAPGRCIntegrationLibrary();
    Map roleDates = sapgrc.getBusinessRoleDates(wfcontext);
    SailPointContext spContext = wfcontext.getSailPointContext();
    Attributes args = wfcontext.getArguments();
    ProvisioningProject project = (ProvisioningProject) args.get("project");
    Map entitlementExpand = sapgrc.getBusinessRoleChckngCommonEntl(wfcontext);

   /*
    * The rule iterates the provisioning plan and fetches the sunrise and sunset dates set
    * in the provisioning project and sets in the provisioning plan arguments.
    */
    for (ProvisioningPlan plan : Util.iterate(project.getPlans())) {
        String targetIntegration = plan.getTargetIntegration();
        if (sapgrc.isSAPDirectApplication(targetIntegration, spContext)) {
        for (AccountRequest accReq : Util.iterate(plan.getAccountRequests())) {
            for (ProvisioningPlan.AttributeRequest attReq : Util.iterate(accReq.getAttributeRequests())) {
                String attrName = attReq.getName();
                if (SAPConnector.ATTR_ROLES.equalsIgnoreCase(attrName)) {
                /*
                 * If the attribute request contains SAP group schema Roles then
                 * Expansion items is being iterated and SAP role being provisioned in account request
                 * is checked with the list of entiltlements included in the expansion items of business role
                 * if it matches, then the sunrise and sunset dates of that specific business role is assigned to the
                 * SAP role being provisioined.
                 */
                       Date sunriseDate, sunsetDate = null;
                       Object entitlementNameObject = attReq.getValue();
                       String endDateString = null,startDateString = null;

                       // dates passed from the workflow, if is an instance of string
                       // set it in the argument.
                       if (startDate instanceof String) {
                          if (startDate!= null) {
                              startDateString = startDate;
                          }
                       }
                       if (endDate instanceof String) {
                          if (endDate!= null) {
                              endDateString = endDate;
                          }
                       }

                        if (attReq.getArguments() != null) {
                            sunriseDate = attReq.getArguments().getDate(SUNRISE_DATE);
                            sunsetDate = attReq.getArguments().getDate(SUNSET_DATE);
                        }

                        if (entitlementNameObject instanceof String) {
                           String entitlementName = (String)entitlementNameObject;
                           // dates passed from the workflow, if is an instance of map,
                           // we fetch the value by passing the entitlement name
                            if (startDate instanceof Map) {
                              startDateString = startDate.get(entitlementName);
                            }
                            if (endDate instanceof Map) {
                                endDateString = endDate.get(entitlementName);
                            }
                           if (!Util.isEmpty(entitlementExpand) && entitlementExpand.containsKey(entitlementName)) {
                              Map dates = getDates(roleDates,entitlementExpand,entitlementName);
                              if (!Util.isEmpty(dates)) {
                                 sunriseDate = (Date) dates.get(SUNRISE_DATE);
                                 sunsetDate = (Date) dates.get(SUNSET_DATE);
                              }
                           }
                       }
                       else if (entitlementNameObject instanceof List) {
                           List entilementList = (List)entitlementNameObject;
                           for (String entitlement : entilementList) {
                           // dates passed from the workflow, if is an instance of map,
                           // we fetch the value by passing the entitlement name
                           if (startDate instanceof Map) {
                               startDateString = startDate.get(entitlement);
                           }
                           if (endDate instanceof Map) {
                               endDateString = endDate.get(entitlement);
                           }
                            if (!Util.isEmpty(entitlementExpand) && entitlementExpand.containsKey(entitlement)) {
                                 Map dates = getDates(roleDates,entitlementExpand,entitlement);
                                 if (!Util.isEmpty(dates)) {
                                    sunriseDate = (Date) dates.get(SUNRISE_DATE);
                                    sunsetDate = (Date) dates.get(SUNSET_DATE);
                                }
                             }
                          }
                        }

                        if (sunriseDate != null) {
                            startDateString = Util.dateToString(sunriseDate,GRCRequestDateFormatString);
                        }

                        if (sunsetDate != null) {
                            endDateString = Util.dateToString(sunsetDate,GRCRequestDateFormatString);
                        }

                       if (attReq.getArguments() == null) {
                           Attributes args = new Attributes();
                           if (!Util.isEmpty(endDateString)) {
                              args.put("endDate", endDateString);
                           }
                           if (!Util.isEmpty(startDateString)) {
                             args.put("startDate", startDateString);
                           }
                          attReq.setArguments(args);
                        } else {
                           if (!Util.isEmpty(endDateString)) {
                             attReq.getArguments().put("endDate", endDateString);
                           }
                           if (!Util.isEmpty(startDateString)) {
                             attReq.getArguments().put("startDate", startDateString);
                           }
                        }
                     }
                  }
                }
              }
            }
         } catch(Exception e) {
             if (log.isErrorEnabled()) {
                log.error("Exception setting dates in provisioning plan", e);
             }
         }


import sailpoint.object.Filter;
import sailpoint.object.Identity;
import sailpoint.web.modeler.RoleConfig;
RoleConfig rc = new RoleConfig();
return Filter.in("type", rc.getManuallyAssignableRoleTypes());

//
// This rule is used to correlate an SSO provider claim to an IdentityIQ identity. It will attempt
// to use the "default" claim as the variable and look up the Identity based on email or
// user object identifier. In the case of Azure Active Directory, the default claim is "nameId".
// It will look for an "@" in the value. If found, assume we should correlate via the Identity
// email address; otherwise, assume the value is the user object identifier and correlate via
// the Link nativeIdentity property.
//
// This rule depends on a new application property (tenantId) added in Release 8.3. It will use that property
// to find the application to which the authenticating user should belong. The tenant is stored in the
// application attributes.
//
import sailpoint.object.Identity;
import sailpoint.object.Application;
import sailpoint.tools.JsonHelper;
import sailpoint.api.ObjectUtil;
import sailpoint.tools.Util;

log.debug("Azure Active Directory SAML Rule Starting");

Identity identity;

if (assertionAttributes != null && !assertionAttributes.isEmpty()) {
    // log the provided claims
    log.debug("===== Claims Start =====");
    log.debug(JsonHelper.toJson(assertionAttributes));
    log.debug("===== Claims End =====");

    // this is the tenant ID or identifier of the application. It will be used to find the configured AD application.
    String tenantIdProp = "http://schemas.microsoft.com/identity/claims/tenantid";

    // this should be set to the default claim used by the active directory. It will contain the value used to look up an identity
    String defaultProp = "nameId";   // default property that can be mapped to any claim on the AD side

    // get the value associated with correlation property
    String defaultPropValue = (String) assertionAttributes.get(defaultProp);

    // the the tenant ID value
    String tenantId = (String) assertionAttributes.get(tenantIdProp);

    log.debug("Default Prop: " + defaultProp);
    log.debug("Default Prop Value: " + defaultPropValue);
    log.debug("Tenant ID: " + tenantId);

    if (tenantId != null) {
        // look up AD application by tenant ID - this assumes Azure only - add others as needed
        // the tenant ID is a property added during the Azure application creation and stored as an attribute (tenantId)
        Application app = ObjectUtil.getApplicationByAttribute("tenantId", tenantId, Arrays.asList("Azure Active Directory"), context);

        if (app != null) {
            // if the value looks like an email address, find Identity by email; otherwise, assume it is the nativeIdentity in the Link
            if (defaultPropValue.contains("@")) {
                log.debug("Correlating IIQ user by email.");

                List<Identity> identities = ObjectUtil.getIdentitiesFromEmail(context, defaultPropValue);

                if (identities == null || identities.isEmpty()) {
                    log.warn("No IIQ Identity found for " + defaultPropValue + ".");
                }
                else if (identities.size() > 1) {
                    log.warn("More than one Identity matched " + defaultPropValue + ". Cannot determine proper object.");
                }
                else {
                    identity = identities.get(0);
                }
            }
            else {
                log.debug("Correlating IIQ user by Link nativeIdentity.");

                String identityId = ObjectUtil.getIdentityFromLink(context, app, null, defaultPropValue);

                if (Util.isNotNullOrEmpty(identityId)) {
                    identity = context.getObjectById(Identity.class, identityId);
                }
                else {
                    log.warn("No Identity found for Application '" + tid + "' and AD user '" + defaultPropValue + "'.");
                }
            }

            if (identity == null) {
                log.warn("IIQ user could not be found using property value: " + defaultPropValue);
            }
            else {
                log.debug("Found matching Identity (" + identity.getName() + ") for " + defaultPropValue + ".");
            }
        }
        else {
            log.warn("Unable to authenticate user because the application with tenant ID " + tenantId + " does not exist.");
        }
    }
    else {
        log.warn("Unable to authenticate user because of missing application tenant ID value.");
    }
}
else {
    log.warn("No assertion attributes provided from SSO provider.");
}

log.debug("Azure Active Directory SAML Rule Finished");

return identity;


import java.util.*;
import sailpoint.api.*;
import sailpoint.api.nativeidentitychange.*;
import sailpoint.object.*;
import sailpoint.request.*;
import sailpoint.tools.*;

Set<String> modifiedWidgetIds = new HashSet<String>();

// Iterate over the Widgets being changed, using the util method to get an iterator. The third argument
// takes an optional filter but we don't need one here since we're looking at all Widgets.
Iterator<String> widgetIdIterator = NativeIdentityChangeUtil.getIdIterator(context, Widget.class, null);
while (widgetIdIterator.hasNext()) {
    String widgetId = widgetIdIterator.next();

    // Skip this object if it's already been processed
    if (propagator.hasObjectProcessed(Widget.class, widgetId)) {
        continue;
    }

    try {
        Widget widget = ObjectUtil.transactionLock(context, Widget.class, widgetId);

        boolean isUpdated = false;

        // Iterate over all the change events
        for (NativeIdentityChangeEvent event : events) {
            // For each change event, rename all the DNs found in the widget's identity selector, using the
            // util method to do the heavy lifting. Toggle the isUpdated method appropriately.
            IdentitySelector selector = widget.getSelector();
            if (selector != null) {
                isUpdated |= NativeIdentityChangeUtil.renameNativeIdentityInIdentitySelector(event.getOldNativeIdentity(),
                        event.getNewNativeIdentity(), selector, event.getApplicationId());
            }
        }

        if (isUpdated) {
            context.saveObject(widget);
            context.commitTransaction();
            context.decache(widget);
            modifiedWidgetIds.add(widgetId);
        }

    } catch (ObjectAlreadyLockedException ex) {
        throw new RequestTemporaryException("The Widget object was locked; aborting propagation but the request will be retried.", ex);
    } finally {
        // Release the lock even if the widget was not changed
        context.commitTransaction();
    }

    // Mark this object as processed
    propagator.markObjectProcessed(Widget.class, widgetId);
}

taskResult.setAttribute("widgetsUpdated", modifiedWidgetIds.size());

return true;

