  String tableName = "USR02";
  String id = object.getString("User Name");
  String delimiter = "#";

  //This list contains the columns that needs to be fetched from the table
  selColumn.add("BNAME");
  selColumn.add("LTIME");
  selColumn.add("PWDSTATE");
  selColumn.add("TRDAT");

  //listQuery is the filter criteria for the query. Here columns are replaced by double
  //question marks(??) and values are replaced by double ampersand(&&). When using IN
  //for select criteria, do not enclose values with brackets.
  String listQuery = "?? IN && AND ?? EQ &&";

  //The value here should be columns that are used in place of double question marks
  //in the query. They should be backward slash separated and will be replace in the
