  String listConditionField = "USTYP/BNAME";

  //This list will have the values that needs to be added in the query and
  //will replace double ampersands.
  //There needs to be a format followed for this.
  //If the query contains IN, then it needs to be added as comma separated values
  //For other fields, just add the value in the list. It should be noted that
  //the order in which value is added is important.
  listConditionValue.add(Collections.singletonList("A,B"));
  listConditionValue.add(Collections.singletonList(id));

  //querySAPTableWithSPBAPI is the method that will return the list of delimiter specified values.
  // The last value in the method will depend if select one or multiple criteria. If it is single
  //then new SingleFieldConditionQueryForSPBAPI() else use new MultiFieldQueryForSPBAPI()
  resultList = connector.querySAPTableWithSPBAPI(destination,tableName,listConditionValue,selColumn,delimiter,
  sailFMName, listQuery,listConditionField,new MultiFieldQueryForSPBAPI());

} catch ( Exception e ) {
  e.printStackTrace();
}

