  /**
	 * @param SailPointContext context
	 * @param StringBuilder csvFile
	 * @param QueryOptions certQuery
	 * @return StrigBuilder csvFile
	 * @throws GeneralException
	 */
  private static StringBuilder getCertificationDetails(SailPointContext context, StringBuilder csvFile, QueryOptions certQuery) throws GeneralException {
    logger.debug("Entered into getCertificationDetails() method");

    if (context == null && csvFile == null && certQuery == null) {
      throw new IllegalArgumentException("context or StringBuilder or QueryOptions cannot be null or empty");
    }
    logger.info("String Builder File Data is " + csvFile.toString());
    logger.info("Fetcting Certification Objects By Using this QueryOptions: " + certQuery.toString());

    int certCount = context.countObjects(Certification.class, certQuery);
    logger.debug("Certification Objects count is " + certCount);

    log.error(certCount);

    if (certCount > 0) {
      Iterator<Certification> certResults = context.search(Certification.class, certQuery);
      while (certResults != null && certResults.hasNext()) {
        Certification certification = (Certification) certResults.next();
        String certificationPhase = certification.getPhase().toString();
        int participantsCount = certification.getTotalEntities();

        log.error(participantsCount);

        if (participantsCount > 0) {

          Set uniqueLines = new HashSet();

          List<CertificationEntity> certificationParticipantsList = certification.getEntities();
          if (Util.nullSafeSize(certificationParticipantsList) > 0) {
            for (CertificationEntity certificationParticipant : certificationParticipantsList) {
              String participantName = certificationParticipant.getIdentity();
              String departmentInfo = getDepartmentAudit(context, participantName);

              // update below code
              String csvLine = participantName + "," + departmentInfo;

              if (!uniqueLines.contains(csvLine)) {
                uniqueLines.add(csvLine);
                csvFile.append(csvLine).append("\n");
              }

              // data appending to csv file 
              csvFile.append(participantName != null ? participantName : "N/A").append(",");
              csvFile.append(departmentInfo != null ? departmentInfo : "N/A").append("\n");

            }
          }
        }
      }
    }
    logger.debug("Exiting into getCertificationDetails() method");
    return csvFile;
  }

  /**
	 * @param context
	 * @param participantName
	 * @return departmentAudit
	 */
  private static String getDepartmentAudit(SailPointContext context, String participantName) {
    logger.trace("Entered into getDepartmentAudit() method");
    if (Util.isNullOrEmpty(participantName)) {
      throw new IllegalArgumentException("Participant Name cannot be null or empty");
    }
    String departmentAudit = null;
    try {
      Filter auditTargetFilter = Filter.eq("target", "Identity:" + participantName);
      logger.trace("Fetcing Audit Event by Using this Filter: " + auditTargetFilter.toXml());
      AuditEvent auditEvent = context.getUniqueObject(AuditEvent.class, auditTargetFilter);
      if ( auditEvent != null ) { departmentAudit = auditEvent.getString4(); }
      logger.debug("Identity: " + participantName + " department Info: " + departmentAudit);
    } catch (GeneralException e) {
      logger.error("An Error occured due to " + e.getMessage());
    }
    logger.trace("Exiting into getDepartmentAudit() method");
    return departmentAudit;
  }

