  // Rule START

  /***************************************************************************************************************************************************************************
  *																																																																																					 *	
  *																														Mover - PAM roles Targeted Certification Rule								        																					 *
  *																																																																																					 *
  ***************************************************************************************************************************************************************************/

  Log logger = LogFactory.getLog("rule.worldbankgroup.MoverPAMTargetedCertification");

  String ruleName = "Mover - PAM Targeted Certification Rule";
  String certificationName = "Mover - PAM roles Targeted Certification";

  String enterString = "Enter rule: " + ruleName;
  String exitString = "Exit rule: " + ruleName;
  logger.info(enterString);

  StringBuilder csvFile = new StringBuilder();

  String csvHeader = "Creation Date,Certification Status,Completion Percentage,Participant Name,Department\n";
  csvFile.append(csvHeader);

  Filter moverStartFilter = Filter.like("name", "PAM Roles Review for Mover Event", Filter.MatchMode.START);

  QueryOptions qo = new QueryOptions();
  qo.setCloneResults(true);
  qo.setOrderBy("created");
  qo.setOrderAscending(true);
  qo.addFilter(moverStartFilter);

  int count = context.countObjects(CertificationGroup.class, qo);
  logger.debug(certificationName + " Objects count is " + count);


  if (count > 0) {
    Iterator certGroupResults = context.search(CertificationGroup.class, qo, "id");
    while (certGroupResults != null && certGroupResults.hasNext()) {
      Object[] obj = (Object[]) certGroupResults.next();
      String certificationGropId = (String) obj[0];
      logger.debug("Certification Group ID: " + certificationGropId);
      CertificationGroup certGroup = context.getObjectById(CertificationGroup.class, certificationGropId);
      String delimiter = " | ";
      Date certificationCreatedDate = certGroup.getCreated();
      int certCompletionPercentage = certGroup.getPercentComplete();
      String certificationStatus = certGroup.getStatus().toString();

      CertificationDefinition definition = certGroup.getDefinition();
      String certDefinitionId = definition.getId();

      Filter certIdFilter = Filter.eq("certificationDefinitionId", certDefinitionId);
      QueryOptions certQuery = new QueryOptions();
      certQuery.addFilter(certIdFilter);

      csvFile = getCertificationDetails(context, csvFile, certQuery);
    }
  }
  logger.info(exitString);
  // Rule END


  return csvFile.toString();

